// ─────────────────────────────────────────────────────────────────────────
// Smart Excel parsing — auto-skips metadata rows above the real header row
// ─────────────────────────────────────────────────────────────────────────
function findHeaderRow(matrix, expectedHeaders = []) {
  // Scan first 15 rows; pick the first row where:
  //  (a) at least N non-empty cells, AND
  //  (b) ideally matches one of the expected headers
  const lim = Math.min(15, matrix.length);
  for (let i = 0; i < lim; i++) {
    const row = matrix[i] || [];
    const nonEmpty = row.filter(c => c !== null && c !== undefined && String(c).trim() !== '').length;
    if (nonEmpty < 3) continue;
    if (expectedHeaders.length === 0) {
      if (nonEmpty >= 5) return i;
      continue;
    }
    const lower = row.map(c => String(c ?? '').trim().toLowerCase());
    const matches = expectedHeaders.filter(h => lower.some(c => c === h.toLowerCase())).length;
    if (matches >= Math.min(2, expectedHeaders.length)) return i;
  }
  // Fallback: first row with ≥3 non-empty cells
  for (let i = 0; i < lim; i++) {
    const row = matrix[i] || [];
    const nonEmpty = row.filter(c => c !== null && c !== undefined && String(c).trim() !== '').length;
    if (nonEmpty >= 3) return i;
  }
  return 0;
}

async function parseExcelSmart(arrayBuffer, expectedHeaders = []) {
  const XLSX = await getXLSX();
  const wb = XLSX.read(arrayBuffer, { cellDates: true });
  const sheet = wb.Sheets[wb.SheetNames[0]];
  // Read as 2D array first (no header inference)
  const matrix = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: null });
  if (!matrix.length) return { headers: [], rows: [] };

  const headerIdx = findHeaderRow(matrix, expectedHeaders);
  const rawHeaders = matrix[headerIdx] || [];
  const headers = rawHeaders.map((h, i) => {
    const s = String(h ?? '').trim();
    return s || `__col_${i}__`;
  });

  const rows = [];
  for (let i = headerIdx + 1; i < matrix.length; i++) {
    const row = matrix[i] || [];
    const nonEmpty = row.filter(c => c !== null && c !== undefined && String(c).trim() !== '').length;
    if (nonEmpty === 0) continue; // skip blank rows
    const obj = {};
    headers.forEach((h, j) => { obj[h] = row[j] ?? ''; });
    rows.push(obj);
  }
  // Filter out placeholder columns from header list
  const realHeaders = headers.filter(h => !h.startsWith('__col_'));
  return { headers: realHeaders, allHeaders: headers, rows };
}

// ─────────────────────────────────────────────────────────────────────────
// FNAC sales export parser — formato "Vendas detalhadas com margem"
// Estrutura fixa: linha 1 título, linha 2 "Data: dd-mm-yyyy até dd-mm-yyyy",
// linha 3 "Loja: X", linha 4 headers (17 cols), dados a partir da linha 5.
// ─────────────────────────────────────────────────────────────────────────
// v3.20.17: tenta usar Web Worker para não bloquear UI. Fallback para main thread
// se o worker falhar (CDN bloqueado, browser antigo, etc.).
function parseFnacSalesExcel(file, onProgress) {
  return new Promise((resolve, reject) => {
    // Tentar via Web Worker primeiro
    if (typeof Worker !== 'undefined') {
      try {
        const worker = new Worker('/workers/fnacSalesWorker.js');
        const reader = new FileReader();
        reader.onload = (e) => {
          worker.postMessage({
            type: 'parse',
            payload: { arrayBuffer: e.target.result, filename: file.name },
          }, [e.target.result]); // transferable → zero-copy
        };
        reader.onerror = () => { worker.terminate(); reject(reader.error); };
        worker.onmessage = (ev) => {
          const { type, result, error, ...rest } = ev.data;
          if (type === 'progress') { onProgress && onProgress(rest); }
          else if (type === 'done')  { worker.terminate(); resolve(result); }
          else if (type === 'error') { worker.terminate(); reject(new Error(error)); }
        };
        worker.onerror = (err) => {
          worker.terminate();
          // Fallback transparente para main thread
          parseFnacSalesExcelMainThread(file).then(resolve).catch(reject);
        };
        reader.readAsArrayBuffer(file);
        return;
      } catch (e) {
        // Fallback se worker falhar a inicializar
        parseFnacSalesExcelMainThread(file).then(resolve).catch(reject);
        return;
      }
    }
    parseFnacSalesExcelMainThread(file).then(resolve).catch(reject);
  });
}

// Implementação main-thread (fallback ou primeira versão)
function parseFnacSalesExcelMainThread(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const XLSX = await getXLSX();
        const wb = XLSX.read(new Uint8Array(e.target.result), { type: 'array', cellDates: true });
        const sheetName = wb.SheetNames.find(n => /vendas/i.test(n)) || wb.SheetNames[0];
        if (!sheetName) return reject(new Error('Sem sheet no ficheiro'));
        const sheet = wb.Sheets[sheetName];
        const aoa = XLSX.utils.sheet_to_json(sheet, { header: 1, blankrows: false, defval: null });
        if (aoa.length < 5) return reject(new Error('Ficheiro vazio ou formato inesperado'));

        // Meta — linhas 1, 2, 3 (índices 0,1,2)
        const metaLine2 = (aoa[1] || []).filter(Boolean).join(' ');
        const metaLine3 = (aoa[2] || []).filter(Boolean).join(' ');
        const periodMatch = metaLine2.match(/Data:\s*(\d{2}-\d{2}-\d{4})\s*at[ée]\s*(\d{2}-\d{2}-\d{4})/i);
        const storeMatch  = metaLine3.match(/Loja:\s*(.+?)(?:\s*(?:Valor|Margem|Descontos|$))/i);
        const dateFrom = periodMatch ? toIsoDate(periodMatch[1]) : null;
        const dateTo   = periodMatch ? toIsoDate(periodMatch[2]) : null;
        const storeName = storeMatch ? storeMatch[1].trim() : '—';

        // Headers — linha 4 (índice 3). Posicionais com fuzzy fallback.
        const headers = (aoa[3] || []).map(h => String(h || '').trim().toLowerCase());
        const colIdx = (patterns) => {
          for (let i = 0; i < headers.length; i++) {
            if (patterns.some(p => headers[i].includes(p))) return i;
          }
          return -1;
        };
        const cEan    = colIdx(['ean']);
        const cInt    = colIdx(['interno', 'cód', 'cod']);
        const cName   = colIdx(['descri', 'nome']);
        const cQty    = colIdx(['qtd', 'quant']);
        const cPvp    = colIdx(['pvp s/iva', 'pvp sem']);                    // procura "PVP S/IVA" antes
        const cPvpVat = colIdx(['pvp']) !== cPvp ? colIdx(['pvp']) : -1;     // depois o outro PVP (com IVA)
        const cPmp    = colIdx(['pmp']);
        const cDcom   = colIdx(['d.comercial', 'd. comercial', 'comerc']);
        const cDfid   = colIdx(['d.fidelidade', 'd. fidelidade', 'fidel']);
        const cDate   = colIdx(['data']);
        const cPos    = colIdx(['pos']);
        const cTrx    = colIdx(['transa']);
        const cFam1   = colIdx(['famila 1', 'família 1', 'familia 1']);
        const cFam2   = colIdx(['famila 2', 'família 2', 'familia 2']);
        const cFam3   = colIdx(['famila 3', 'família 3', 'familia 3']);

        if (cEan < 0 || cName < 0 || cQty < 0 || cPvp < 0 || cPmp < 0) {
          return reject(new Error('Cabeçalho não tem as colunas esperadas (EAN, Descrição, Qtd, PVP S/IVA, PMP).'));
        }

        const rows = [];
        for (let r = 4; r < aoa.length; r++) {
          const row = aoa[r];
          if (!row) continue;
          const ean = row[cEan];
          if (ean == null || ean === '') continue;
          const qty       = Number(row[cQty]) || 0;
          const pvpNoVat  = Number(row[cPvp]) || 0;
          const pvp       = cPvpVat >= 0 ? (Number(row[cPvpVat]) || 0) : pvpNoVat;
          const pmp       = Number(row[cPmp]) || 0;
          const discComerc = cDcom >= 0 ? (Number(row[cDcom]) || 0) : 0;
          const discFidel  = cDfid >= 0 ? (Number(row[cDfid]) || 0) : 0;
          const margem    = pvpNoVat - pmp;
          const margemPct = pvpNoVat !== 0 ? (margem / pvpNoVat * 100) : 0;
          const revenue   = qty * pvpNoVat; // negativo se devolução (qty < 0)
          let dateIso = null;
          let hour = null;
          let dow = null; // 0=domingo, 1=segunda, ..., 6=sábado
          const rawDate = cDate >= 0 ? row[cDate] : null;
          if (rawDate instanceof Date) {
            dateIso = rawDate.toISOString().slice(0, 10);
            hour = rawDate.getUTCHours();
            dow  = rawDate.getUTCDay();
          } else if (typeof rawDate === 'string' && rawDate.length >= 10) {
            dateIso = rawDate.slice(0, 10);
            if (rawDate.length >= 13) hour = parseInt(rawDate.slice(11, 13), 10);
            const d = new Date(rawDate);
            if (!isNaN(d.getTime())) dow = d.getUTCDay();
          }
          rows.push({
            ean: String(ean),
            internal: cInt >= 0 ? String(row[cInt] || '').trim() : '',
            name: String(row[cName] || '').trim(),
            qty,
            pvp, pvpNoVat, pmp,
            discComerc, discFidel,
            margem, margemPct,
            revenue,
            date: dateIso, hour, dow,
            pos: cPos >= 0 ? row[cPos] : null,
            transactionId: cTrx >= 0 ? row[cTrx] : null,
            fam1: cFam1 >= 0 ? String(row[cFam1] || '').trim() : '',
            fam2: cFam2 >= 0 ? String(row[cFam2] || '').trim() : '',
            fam3: cFam3 >= 0 ? String(row[cFam3] || '').trim() : '',
          });
        }

        const importedAt = new Date().toISOString();
        const id = `${storeName.toLowerCase().replace(/\s+/g, '-')}-${importedAt.replace(/[:.]/g, '')}`;
        resolve({
          id,
          store: storeName,
          filename: file.name,
          dateFrom, dateTo, importedAt,
          rowsCount: rows.length,
          rows,
        });
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = () => reject(reader.error);
    reader.readAsArrayBuffer(file);
  });
}

