// ─────────────────────────────────────────────────────────────────────────
// v3.22.0: Planta interactiva — parse do Excel planograma (AVEIRO_PLANTA.xlsx)
// Lê NOMENCLATURA (metadados por móvel) + folhas PISO 1/PISO 2 (grelha visual:
// cada célula mergeada/colorida = um móvel). A posição na grelha É a geometria.
// Mapeamento Excel→app: "PISO 1"→"PISO 0" (térreo), "PISO 2"→"PISO 1" (cima).
// ─────────────────────────────────────────────────────────────────────────
const PLANTA_FLOOR_MAP = { 'PISO 1': 'PISO 0', 'PISO 2': 'PISO 1' };

function parsePlantaExcel(file, onProgress) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const XLSX = await getXLSX();
        onProgress?.({ stage: 'parse', message: 'A ler planta…' });
        const wb = XLSX.read(new Uint8Array(e.target.result), { type: 'array', cellStyles: true });

        // 1) NOMENCLATURA → metadados por número de móvel
        const meta = {};
        const nomName = (wb.SheetNames || []).find(n => /NOMENCLATURA/i.test(n));
        if (nomName) {
          const nom = XLSX.utils.sheet_to_json(wb.Sheets[nomName], { header: 1, defval: null, blankrows: true });
          for (let i = 1; i < nom.length; i++) {
            const row = nom[i]; if (!row) continue;
            const num = row[0]; if (num == null) continue;
            const key = String(num).trim();
            meta[key] = {
              dept: row[1] || '', produit: row[2] || '', section: row[3] || '',
              mobilier: row[5] || '', floor: row[6] || '',
            };
          }
        }

        // 2) Cada folha PISO N → grelha de móveis
        const parseFloor = (sheetName) => {
          const ws = wb.Sheets[sheetName];
          if (!ws || !ws['!ref']) return null;
          const ref = XLSX.utils.decode_range(ws['!ref']);
          const rows = ref.e.r + 1, cols = ref.e.c + 1;
          const merges = ws['!merges'] || [];
          const mergeTL = {}; const covered = new Set();
          for (const m of merges) {
            mergeTL[m.s.r + '_' + m.s.c] = { rs: m.e.r - m.s.r + 1, cs: m.e.c - m.s.c + 1 };
            for (let r = m.s.r; r <= m.e.r; r++)
              for (let c = m.s.c; c <= m.e.c; c++)
                if (r !== m.s.r || c !== m.s.c) covered.add(r + '_' + c);
          }
          const palette = []; const palIdx = {};
          const pidx = (hex) => {
            if (!hex) return -1;
            if (!(hex in palIdx)) { palIdx[hex] = palette.length; palette.push(hex); }
            return palIdx[hex];
          };
          const cells = []; const fixtures = [];
          for (let r = 0; r < rows; r++) {
            for (let c = 0; c < cols; c++) {
              if (covered.has(r + '_' + c)) continue;
              const cell = ws[XLSX.utils.encode_cell({ r, c })];
              if (!cell) continue;
              let fill = '';
              try {
                const f = cell.s && cell.s.fgColor && cell.s.fgColor.rgb;
                if (f && typeof f === 'string') fill = (f.length === 8 ? f.slice(2) : f);
              } catch { /* no style */ }
              if (fill === 'FFFFFF') fill = '';
              const v = cell.v != null ? String(cell.v).trim() : '';
              const span = mergeTL[r + '_' + c] || { rs: 1, cs: 1 };
              if (fill) cells.push([r, c, span.rs, span.cs, pidx(fill)]);
              if (v) {
                const numMatch = /^\d+(\s*bis)?$/i.test(v);
                const num = numMatch ? v.replace(/\s*bis/i, '').trim() : null;
                const m = (num && meta[num]) ? meta[num] : null;
                fixtures.push({
                  r, c, rs: span.rs, cs: span.cs, label: v, fill: fill || null,
                  num: num ? Number(num) : null,
                  dept: m ? m.dept : null, produit: m ? m.produit : null, mobilier: m ? m.mobilier : null,
                });
              }
            }
          }
          return {
            name: PLANTA_FLOOR_MAP[sheetName.trim()] || sheetName.trim(),
            srcName: sheetName.trim(),
            cols, rows, palette, cells, fixtures,
          };
        };

        const floors = [];
        for (const sn of (wb.SheetNames || [])) {
          if (/^PISO\s/i.test(sn.trim())) {
            const f = parseFloor(sn);
            if (f) floors.push(f);
          }
        }
        if (floors.length === 0) { reject(new Error('Nenhuma folha "PISO N" encontrada na planta.')); return; }
        onProgress?.({ stage: 'done', message: `${floors.length} pisos lidos` });
        resolve({ floors, filename: file.name, parsedAt: new Date().toISOString() });
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = () => reject(new Error('Erro ao ler ficheiro'));
    reader.readAsArrayBuffer(file);
  });
}

function parsePenetrationExcel(file, onProgress, opts = {}) {
  const sellerStoreFilter = (opts.sellerStoreFilter || 'AVEIRO').toUpperCase();
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const XLSX = await getXLSX();
        onProgress?.({ stage: 'parse', message: 'A ler ficheiro…' });
        // Truque chave: sheets:['RESUMO','VENDEDOR_TOTAL'] reduz dramaticamente
        // a memória — só carrega estas duas sheets. Ficheiro tem 25 sheets, ~96MB.
        const wb = XLSX.read(new Uint8Array(e.target.result), {
          type: 'array', cellDates: false,
          // v3.21.16: análise profunda — 10 sheets parsadas (~96MB total, mas
          // só as sheets pequenas/médias; BD* e PIVOT* gigantes ficam de fora).
          // v3.21.23: BD N + BD N-1 → daily real por loja (RESUMO DIA é só company-wide)
          sheets: ['RESUMO', 'VENDEDOR_TOTAL', 'BUDGET LOJA', 'RESUMO DIA', 'TP Escalões', 'TOTAL VIM', 'Churn Loja', 'Churn', 'AUX_1', 'Aux_Target', 'BD TT SEGUROS', 'BD N', 'BD N-1'],
        });
        const sh = wb.Sheets['RESUMO'];
        if (!sh) return reject(new Error('Sheet "RESUMO" não encontrada no ficheiro.'));
        const aoa = XLSX.utils.sheet_to_json(sh, { header: 1, blankrows: false, defval: null });
        if (aoa.length < 6) return reject(new Error('Sheet RESUMO vazia.'));
        // R5 .. último = lojas; última linha = TOTAL
        const extract = (row) => {
          const out = {};
          for (const cat of PENETRATION_CATEGORIES) {
            const equip = Number(row[cat.col]) || 0;
            const seg   = Number(row[cat.col + 1]) || 0;
            const taxa  = Number(row[cat.col + 2]) || 0;
            out[cat.key] = { equip, seg, taxa };
          }
          out.addonRate = Number(row[42]) || 0; // TP ADDON %
          out.deliveryPct = Number(row[80]) || 0; // TX ENTREGA PP
          return out;
        };
        const stores = [];
        let total = null;
        for (let r = 5; r < aoa.length; r++) {
          const row = aoa[r];
          if (!row) continue;
          const name = row[1];
          if (!name || typeof name !== 'string') continue;
          const data = { name: name.trim(), ...extract(row) };
          if (data.name.toUpperCase() === 'TOTAL') { total = data; continue; }
          stores.push(data);
        }
        if (stores.length === 0) return reject(new Error('Sem lojas no ficheiro.'));
        if (!total) {
          // fallback: calcula média ponderada
          const sums = {};
          for (const cat of PENETRATION_CATEGORIES) sums[cat.key] = { equip: 0, seg: 0 };
          for (const s of stores) for (const cat of PENETRATION_CATEGORIES) {
            sums[cat.key].equip += s[cat.key].equip;
            sums[cat.key].seg   += s[cat.key].seg;
          }
          total = { name: 'TOTAL' };
          for (const cat of PENETRATION_CATEGORIES) {
            const e = sums[cat.key].equip, sg = sums[cat.key].seg;
            total[cat.key] = { equip: e, seg: sg, taxa: e > 0 ? sg / e : 0 };
          }
          total.addonRate = 0;
        }
        // v3.21.12: parse VENDEDOR_TOTAL → lista de vendedores filtrada por loja
        onProgress?.({ stage: 'parse', message: 'A ler colaboradores…' });
        const sellers = [];
        const shV = wb.Sheets['VENDEDOR_TOTAL'];
        if (shV) {
          const aoaV = XLSX.utils.sheet_to_json(shV, { header: 1, blankrows: false, defval: null });
          // Data começa por volta de R6. Filtrar por Loja (col 9) == sellerStoreFilter
          for (let r = 6; r < aoaV.length; r++) {
            const row = aoaV[r];
            if (!row) continue;
            const loja = String(row[9] || '').toUpperCase().trim();
            if (loja !== sellerStoreFilter) continue;
            const name = String(row[7] || '').trim();
            if (!name) continue;
            sellers.push({
              name,
              nif: String(row[8] || '').trim(),
              carga: String(row[10] || '').trim(),
              dept: String(row[12] || '').trim(),
              aux1: String(row[13] || '').trim(), // loja repetida
              taxaLoja: Number(row[19]) || 0,
              taxaAddons: Number(row[15]) || 0,
              telecomU: Number(row[16]) || 0,  // <399€
              telecomO: Number(row[17]) || 0,  // >399€
              vendas: Number(row[49]) || 0,    // total mercadoria
              seguros: Number(row[50]) || 0,
              taxa: Number(row[51]) || 0,      // TP do vendedor
              ddr: Number(row[52]) || 0,
              extraSeg: Number(row[53]) || 0,
              extraCloud: Number(row[54]) || 0,
              planoTotal: Number(row[55]) || 0,
              // Quebra por categoria (vendas/seguros)
              tv:        { v: Number(row[21]) || 0, s: Number(row[22]) || 0 },
              foto:      { v: Number(row[24]) || 0, s: Number(row[25]) || 0 },
              drone:     { v: Number(row[27]) || 0, s: Number(row[28]) || 0 },
              hardware:  { v: Number(row[30]) || 0, s: Number(row[31]) || 0 },
              restart:   { v: Number(row[33]) || 0, s: Number(row[34]) || 0 },
              telecom:   { v: Number(row[37]) || 0, s: Number(row[38]) || 0 },
              smartwatch:{ v: Number(row[40]) || 0, s: Number(row[41]) || 0 },
              mob:       { v: Number(row[43]) || 0, s: Number(row[44]) || 0 },
              gaming:    { v: Number(row[46]) || 0, s: Number(row[47]) || 0 },
              // v3.21.16: campos adicionais — bonificações, PMC, charge-back, VIM
              tpAddon:        Number(row[56]) || 0,
              outrasFamilias: Number(row[65]) || 0,
              totalBimestrais: Number(row[69]) || 0,
              totalSeguros:    Number(row[70]) || 0,
              aLaCarte:        Number(row[71]) || 0,
              aLaCarteValor:   Number(row[72]) || 0,
              objetivoBimestral: Number(row[73]) || 0,
              bonifLoja:       Number(row[74]) || 0,
              bonifBimestral:  Number(row[75]) || 0,
              bonifAddon:      Number(row[76]) || 0,
              challengeSafe:   Number(row[77]) || 0,
              chargeBack:      Number(row[79]) || 0,  // valor de CB
              churnPct:        Number(row[80]) || 0,
              valorDescontoCB: Number(row[81]) || 0,
              vimTotalSCB:     Number(row[82]) || 0,  // VIM total sem charge-back
              pmcApolice:      Number(row[84]) || 0,
              vimTotal:        Number(row[85]) || 0,  // VIM total bruto
            });
          }
          // Ordena por TP desc
          sellers.sort((a, b) => b.taxa - a.taxa);
        }
        // v3.21.14: parse BUDGET LOJA → target total de seguros por loja
        onProgress?.({ stage: 'parse', message: 'A ler budget…' });
        const budgets = {};
        const shB = wb.Sheets['BUDGET LOJA'];
        if (shB) {
          const aoaB = XLSX.utils.sheet_to_json(shB, { header: 1, blankrows: false, defval: null });
          // R0..R2 são headers; data começa em R3
          // Col 0 = Loja, 1 = TARGET, 2 = TARGET À DATA, 3 = REAL, 4 = %, 7 = Diferença
          for (let r = 3; r < aoaB.length; r++) {
            const row = aoaB[r];
            if (!row || !row[0]) continue;
            const lojaName = String(row[0]).toUpperCase().trim();
            budgets[lojaName] = {
              target:    Number(row[1]) || 0,
              targetYtd: Number(row[2]) || 0,
              real:      Number(row[3]) || 0,
              pctAchieved: Number(row[4]) || 0,
              diff:      Number(row[7]) || 0, // negativo = faltam
            };
          }
        }
        // v3.21.16: RESUMO DIA — dados diários N vs N-1 por categoria
        onProgress?.({ stage: 'parse', message: 'A ler dados diários…' });
        const daily = [];
        const shDay = wb.Sheets['RESUMO DIA'];
        if (shDay) {
          const aoaDay = XLSX.utils.sheet_to_json(shDay, { header: 1, blankrows: false, defval: null });
          // Estrutura: R7..end = "Dia X" rows
          // Col 2: "Dia X", col 3: data N (excel serial), col 4: data N-1
          // Por categoria (TV, Foto, HW, Telecom, Smartwatch, Mob, Drone, Gaming, Total):
          //   N: equip(7), seg(8), tp(9) → próximo bloco a +3
          //   N-1: equip(10), seg(11), tp(12)
          //   FOTO N: equip(13), seg(14), tp(15) | FOTO N-1: 16/17/18
          //   HW: 19/20/21 | 22/23/24
          //   Telecom: 25/26/27 | 28/29/30
          //   Smartwatch: 31/32/33 | 34/35/36
          //   Drone: 37/38/39 | 40/41/42  (verificar com Excel layout)
          //   Continua até col ~72
          // Para simplificar: extrair pares (N, N-1) por categoria conhecida.
          // v3.21.20: FIX — ordem real das colunas em RESUMO DIA é
          // TV · FOTO · HARDWARE · TELECOM · SMARTWATCH · RESTART · GAMING · DRONE · MOB · TOTAL
          // (anteriormente: MOB/DRONE/GAMING/TOTAL estavam swapados e RESTART faltava)
          const catCols = [
            { key: 'tv',         n: 7,  n1: 10 },
            { key: 'foto',       n: 13, n1: 16 },
            { key: 'hardware',   n: 19, n1: 22 },
            { key: 'telecom',    n: 25, n1: 28 },
            { key: 'smartwatch', n: 31, n1: 34 },
            { key: 'restart',    n: 37, n1: 40 },
            { key: 'gaming',     n: 43, n1: 46 },
            { key: 'drone',      n: 49, n1: 52 },
            { key: 'mob',        n: 55, n1: 58 },
            { key: 'total',      n: 61, n1: 64 },
          ];
          for (let r = 7; r < aoaDay.length; r++) {
            const row = aoaDay[r];
            if (!row) continue;
            const dia = String(row[2] || '').trim();
            if (!/^Dia\s*\d+/.test(dia)) continue;
            const dayNum = parseInt(dia.replace(/\D/g, ''), 10);
            if (!dayNum) continue;
            const entry = { day: dayNum, dateN: row[3], dateN1: row[4], dow: row[5] };
            let hasData = false;
            for (const c of catCols) {
              const equip   = Number(row[c.n]) || 0;
              const seg     = Number(row[c.n + 1]) || 0;
              const taxa    = Number(row[c.n + 2]) || 0;
              const equipN1 = Number(row[c.n1]) || 0;
              const segN1   = Number(row[c.n1 + 1]) || 0;
              const taxaN1  = Number(row[c.n1 + 2]) || 0;
              entry[c.key] = { equip, seg, taxa, equipN1, segN1, taxaN1 };
              if (equip > 0 || seg > 0) hasData = true;
            }
            entry.hasData = hasData;
            daily.push(entry);
          }
        }

        // v3.21.16: TOTAL VIM — VIM/comissão por loja
        const vim = {};
        const shV2 = wb.Sheets['TOTAL VIM'];
        if (shV2) {
          const aoaV2 = XLSX.utils.sheet_to_json(shV2, { header: 1, blankrows: false, defval: null });
          // R2..end = dados; Col 0 = loja, 1 = BIMESTRAL, 2 = OUTROS, 3 = Tekkie, 4 = TOTAL
          // Col 7 = TP, 8 = Seguros (€), 9 = Addons (€), 10 = Total (€), 11 = Apolices, 15 = Apolices (alt), 16 = VIM Media
          // Col 20 = loja (repeat), 21 = Seguros €, 22 = Addons €, 23 = Total €
          for (let r = 2; r < aoaV2.length; r++) {
            const row = aoaV2[r];
            if (!row || !row[0]) continue;
            const lojaName = String(row[0]).toUpperCase().trim();
            if (lojaName === 'TOTAL') continue;
            vim[lojaName] = {
              bimestral:    Number(row[1]) || 0,
              outros:       Number(row[2]) || 0,
              tekkie:       Number(row[3]) || 0,
              totalUnid:    Number(row[4]) || 0,
              tpRel:        Number(row[7]) || 0,
              segurosEur:   Number(row[8]) || 0,
              addonsEur:    Number(row[9]) || 0,
              totalEur:     Number(row[10]) || 0,
              apolices:     Number(row[11]) || 0,
              vimMediaApolice: Number(row[16]) || 0,
              segEurAlt:    Number(row[21]) || 0,
              addonsEurAlt: Number(row[22]) || 0,
              totalEurAlt:  Number(row[23]) || 0,
            };
          }
        }

        // v3.21.16: Churn Loja (col 4 = loja, col 5 = taxa 6m)
        const churn = {};
        const shC = wb.Sheets['Churn Loja'];
        if (shC) {
          const aoaC = XLSX.utils.sheet_to_json(shC, { header: 1, blankrows: false, defval: null });
          for (let r = 2; r < aoaC.length; r++) {
            const row = aoaC[r];
            if (!row || !row[4]) continue;
            const lojaName = String(row[4]).toUpperCase().trim();
            churn[lojaName] = { taxa6m: Number(row[5]) || 0 };
          }
        }

        // v3.21.16: Churn por colaborador (sheet Churn — col 7=NIF, 8=Apolices, 9=Taxa)
        const sellerChurn = {};
        const shCh = wb.Sheets['Churn'];
        if (shCh) {
          const aoaCh = XLSX.utils.sheet_to_json(shCh, { header: 1, blankrows: false, defval: null });
          for (let r = 1; r < aoaCh.length; r++) {
            const row = aoaCh[r];
            if (!row || !row[7]) continue;
            const nif = String(row[7]).trim();
            if (nif === 'Sem Dados') continue;
            sellerChurn[nif] = {
              apolices: Number(row[8]) || 0,
              taxa:     Number(row[9]) || 0,
            };
          }
        }

        // v3.21.16: TP Escalões — para AVEIRO (apenas escalão Telecom é detalhado)
        const priceScales = { _meta: 'TP por escalão de preço telecom' };
        const shPE = wb.Sheets['TP Escalões'];
        if (shPE) {
          const aoaPE = XLSX.utils.sheet_to_json(shPE, { header: 1, blankrows: false, defval: null });
          // Col 5 = Escalão (global, lista única), col 6 = equip companhia, col 7 = apolices, col 10 = TP
          // Col 0 = escalão (per loja), 1 = loja, 2 = equip, 3 = seg
          const globalScales = [];
          for (let r = 1; r < aoaPE.length; r++) {
            const row = aoaPE[r];
            if (!row) continue;
            // Global (col 5)
            if (row[5] && typeof row[5] === 'string' && row[5].includes('-')) {
              globalScales.push({
                band: row[5],
                equipCia: Number(row[6]) || 0,
                segCia:   Number(row[7]) || 0,
                pesoEquip: Number(row[8]) || 0,
                pesoSeg:   Number(row[9]) || 0,
                tpCia:    Number(row[10]) || 0,
              });
            }
          }
          priceScales.global = globalScales;
          // Per-loja: extrair só AVEIRO
          priceScales.byStore = {};
          let currentBand = null;
          for (let r = 1; r < aoaPE.length; r++) {
            const row = aoaPE[r];
            if (!row) continue;
            if (row[0] && typeof row[0] === 'string' && /\(\d/.test(row[0])) currentBand = row[0];
            const loja = row[1] ? String(row[1]).toUpperCase().trim() : null;
            if (loja && currentBand) {
              if (!priceScales.byStore[loja]) priceScales.byStore[loja] = [];
              priceScales.byStore[loja].push({
                band: currentBand,
                equip: Number(row[2]) || 0,
                seg:   Number(row[3]) || 0,
              });
            }
          }
        }

        // v3.21.16: AUX_1 — cluster por loja (col 20 = loja, 24/25 = loja → cluster?)
        // Estrutura: col 24 = Loja, 25 = Coach. col 17 = LOJA (segunda lista)
        const clusters = {};
        const shA1 = wb.Sheets['AUX_1'];
        if (shA1) {
          const aoaA1 = XLSX.utils.sheet_to_json(shA1, { header: 1, blankrows: false, defval: null });
          // Tenta col 24+25 (Loja → Coach)
          for (let r = 1; r < aoaA1.length; r++) {
            const row = aoaA1[r];
            if (!row) continue;
            if (row[24] && row[25]) {
              const loja = String(row[24]).toUpperCase().trim();
              clusters[loja] = String(row[25]).trim();
            }
          }
        }

        // v3.21.16: Aux_Target — target diário por loja
        const targetsDaily = {};
        const shAT = wb.Sheets['Aux_Target'];
        if (shAT) {
          const aoaAT = XLSX.utils.sheet_to_json(shAT, { header: 1, blankrows: false, defval: null });
          // R0 = headers (col 16 = "Data", col 17+ = lojas)
          const headerRow = aoaAT[0] || [];
          const lojaCols = [];
          for (let c = 17; c < headerRow.length; c++) {
            if (headerRow[c] && typeof headerRow[c] === 'string') {
              lojaCols.push({ col: c, loja: String(headerRow[c]).toUpperCase().trim() });
            }
          }
          // R1..end = linhas de data
          for (let r = 1; r < aoaAT.length; r++) {
            const row = aoaAT[r];
            if (!row || !row[16]) continue;
            const dateSerial = row[16];
            // Excel serial → ISO date (1900-01-01 origin)
            const ms = (Number(dateSerial) - 25569) * 86400 * 1000;
            const d = new Date(ms);
            if (isNaN(d.getTime())) continue;
            const iso = d.toISOString().slice(0, 10);
            for (const { col, loja } of lojaCols) {
              if (row[col] != null) {
                if (!targetsDaily[loja]) targetsDaily[loja] = {};
                targetsDaily[loja][iso] = Number(row[col]) || 0;
              }
            }
          }
        }

        // v3.21.18: BD TT SEGUROS — identificar equipamentos vendidos sem
        // seguro/PP/extensão de garantia, agrupados por família.
        onProgress?.({ stage: 'parse', message: 'A analisar transações…' });
        const uninsured = [];
        const familySummary = {};
        // v3.21.21: declarar uninsuredBySeller no scope correcto (fora do if)
        // para evitar ReferenceError quando a sheet BD TT SEGUROS não existe
        // ou o user faz upload de um ficheiro sem essa sheet.
        const uninsuredBySeller = {};
        const shTT = wb.Sheets['BD TT SEGUROS'];
        if (shTT) {
          const aoaTT = XLSX.utils.sheet_to_json(shTT, { header: 1, blankrows: false, defval: null });
          const ticketMap = new Map(); // ticket_id -> { equips, segs }
          for (let r = 1; r < aoaTT.length; r++) {
            const row = aoaTT[r];
            if (!row || !row[1]) continue;
            const store = String(row[1]).toUpperCase().trim();
            if (store !== sellerStoreFilter) continue;
            const ticket = String(row[2] || '');
            if (!ticket) continue;
            const desc = String(row[8] || '').trim();
            const ean  = String(row[6] || '').trim();
            const qty  = Number(row[9]) || 0;
            const fam1 = row[13] != null ? String(row[13]) : '';
            const fam2 = row[14] != null ? String(row[14]) : '';
            const seller = String(row[11] || '').trim();
            // v3.21.38 fix: regex aceitava só SEG_/SEG  mas o ficheiro tem "SEG-EXT GAR TV…"
            // — antes "SEG-EXT" caía em equips e aparecia listado como equipamento sem seguro
            // (paradoxo: a própria apólice listada como equipamento "sem seguro"). Agora aceita SEG-, PP-, EXT-, etc.
            const isSeg  = /^(SEG|EXT|GAR)[\s_-]/i.test(desc);
            const isPP   = /^PP[\s_-]/i.test(desc);
            const isCard = /Cart[ãa]o.*Prote[çc][ãa]o/i.test(desc);
            const isInsurance = isSeg || isPP || isCard;
            if (!ticketMap.has(ticket)) {
              ticketMap.set(ticket, { equips: [], segs: [], date: row[5] || null });
            }
            const t = ticketMap.get(ticket);
            const item = { desc, ean, qty: Math.abs(qty), fam1, fam2, seller, signed: qty };
            if (isInsurance) t.segs.push(item);
            else if (qty > 0) t.equips.push(item); // ignora devoluções (qty < 0)
          }
          // Identificar uninsured: tickets onde #seguros < #equips
          const uninsuredMap = new Map();
          for (const [ticketId, t] of ticketMap) {
            if (t.equips.length === 0) continue;
            if (t.segs.length >= t.equips.length) continue;
            const uncoveredCount = t.equips.length - t.segs.length;
            // Heurística: os últimos N equipamentos (sem garantia)
            const exposed = t.equips.slice(-uncoveredCount);
            for (const eq of exposed) {
              const key = eq.ean || eq.desc;
              if (!key) continue;
              const family = _famFromDesc(eq.desc, eq.fam1);
              const prev = uninsuredMap.get(key) || {
                ean: eq.ean, desc: eq.desc, fam1: eq.fam1, fam2: eq.fam2,
                qty: 0, tickets: 0, family,
                topSellers: new Map(),
              };
              prev.qty += eq.qty;
              prev.tickets += 1;
              if (eq.seller) prev.topSellers.set(eq.seller, (prev.topSellers.get(eq.seller) || 0) + 1);
              uninsuredMap.set(key, prev);
              // v3.21.19: aggregação por vendedor
              const sellerKey = (eq.seller || '').toUpperCase().trim();
              if (!sellerKey) continue;
              if (!uninsuredBySeller[sellerKey]) {
                uninsuredBySeller[sellerKey] = {
                  totalQty: 0, totalItems: 0, byFamily: {}, items: [],
                  ticketsMap: new Map(),
                };
              }
              const bs = uninsuredBySeller[sellerKey];
              bs.totalQty += eq.qty;
              bs.byFamily[family] = (bs.byFamily[family] || 0) + eq.qty;
              bs.items.push({
                ean: eq.ean, desc: eq.desc, family,
                qty: eq.qty, ticket: ticketId, date: t.date,
              });
              // v3.21.38: vista representativa por talão. Guarda todos os equips +
              // segs do talão para o user ver o contexto completo.
              if (!bs.ticketsMap.has(ticketId)) {
                bs.ticketsMap.set(ticketId, {
                  ticket: ticketId, date: t.date,
                  equips: t.equips.map(e => ({ desc: e.desc, ean: e.ean, qty: e.qty, fam: _famFromDesc(e.desc, e.fam1) })),
                  segs: t.segs.map(s => ({ desc: s.desc, ean: s.ean, qty: s.qty })),
                  uncoveredCount: uncoveredCount,
                });
              }
            }
          }
          // Consolida items por seller (agregar por EAN) e ordena
          for (const sk of Object.keys(uninsuredBySeller)) {
            const bs = uninsuredBySeller[sk];
            const byEan = new Map();
            for (const it of bs.items) {
              const k = it.ean || it.desc;
              if (!k) continue;
              const prev = byEan.get(k);
              if (prev) {
                prev.qty += it.qty;
                prev.tickets += 1;
                if (it.date && (!prev.lastDate || it.date > prev.lastDate)) prev.lastDate = it.date;
              } else {
                byEan.set(k, { ean: it.ean, desc: it.desc, family: it.family, qty: it.qty, tickets: 1, lastDate: it.date || null });
              }
            }
            bs.items = Array.from(byEan.values()).sort((a, b) => b.qty - a.qty).slice(0, 50);
            bs.totalItems = bs.items.length;
            // v3.21.38: converter Map em array ordenado por data desc
            bs.tickets = Array.from(bs.ticketsMap.values())
              .sort((a, b) => (b.date || 0) - (a.date || 0))
              .slice(0, 80);
            delete bs.ticketsMap;
          }
          for (const v of uninsuredMap.values()) {
            // Top vendedor (1)
            const sortedSellers = Array.from(v.topSellers.entries()).sort((a, b) => b[1] - a[1]);
            v.topSeller = sortedSellers[0]?.[0] || '';
            delete v.topSellers;
            uninsured.push(v);
          }
          uninsured.sort((a, b) => b.qty - a.qty);
          // Sumário por família
          for (const u of uninsured) {
            const fam = u.family || 'Outras';
            if (!familySummary[fam]) familySummary[fam] = { count: 0, items: 0, topEans: [] };
            familySummary[fam].count += u.qty;
            familySummary[fam].items += 1;
          }
          // Top 5 EANs por família
          for (const fam of Object.keys(familySummary)) {
            const items = uninsured.filter(u => (u.family || 'Outras') === fam).slice(0, 5);
            familySummary[fam].topEans = items.map(i => ({ ean: i.ean, desc: i.desc, qty: i.qty }));
          }
        }

        // v3.21.23: BD N + BD N-1 → daily real por loja
        onProgress?.({ stage: 'parse', message: 'A analisar BD N (transações)…' });
        function _aggregateBD(sheet, target, targetAll) {
          if (!sheet) return;
          const aoa = XLSX.utils.sheet_to_json(sheet, { header: 1, blankrows: false, defval: null });
          for (let r = 1; r < aoa.length; r++) {
            const row = aoa[r]; if (!row) continue;
            const store = String(row[1] || '').toUpperCase().trim();
            if (!store || store === 'FNAC.PT') continue; // ignora online
            const date = row[6]; if (!date) continue;
            const qty = Number(row[7]) || 0; if (qty <= 0) continue;
            const tipo = String(row[19] || '');
            if (!tipo || tipo === 'VERIFICAR') continue;
            const cat = _catFromTipo(tipo);
            const kind =
              tipo.startsWith('EQUIPAMENTO') ? 'equip' :
              tipo.startsWith('SEGURO')      ? 'seg' :
              tipo.startsWith('ADDON')       ? 'addon' : null;
            if (!kind) continue;
            // Per-store
            if (!target.has(store)) target.set(store, new Map());
            const m = target.get(store);
            if (!m.has(date)) m.set(date, { equip: 0, seg: 0, addon: 0, byCat: {} });
            const agg = m.get(date);
            agg[kind] += qty;
            if (!agg.byCat[cat]) agg.byCat[cat] = { equip: 0, seg: 0, addon: 0 };
            agg.byCat[cat][kind] += qty;
            // Companhia
            if (!targetAll.has(date)) targetAll.set(date, { equip: 0, seg: 0, addon: 0, byCat: {} });
            const allAgg = targetAll.get(date);
            allAgg[kind] += qty;
            if (!allAgg.byCat[cat]) allAgg.byCat[cat] = { equip: 0, seg: 0, addon: 0 };
            allAgg.byCat[cat][kind] += qty;
          }
        }
        const bdStoreMap = new Map();
        const bdAllMap = new Map();
        _aggregateBD(wb.Sheets['BD N'], bdStoreMap, bdAllMap);

        const bdStoreMapN1 = new Map();
        const bdAllMapN1 = new Map();
        _aggregateBD(wb.Sheets['BD N-1'], bdStoreMapN1, bdAllMapN1);

        // Formato compatível com DailyHeatmap actual: { day, total:{equip,seg,taxa}, tv:{equip,seg,taxa}, foto:..., ... }
        function _mapToArray(dateMap) {
          return Array.from(dateMap.entries())
            .sort((a, b) => Number(a[0]) - Number(b[0]))
            .map(([dateSerial, agg]) => {
              const out = {
                day: _dayFromSerial(dateSerial),
                dateSerial: Number(dateSerial),
                hasData: (agg.equip + agg.seg + agg.addon) > 0,
                total: {
                  equip: agg.equip,
                  seg: agg.seg,
                  addon: agg.addon,
                  taxa: agg.equip > 0 ? agg.seg / agg.equip : 0,
                },
              };
              for (const [cat, v] of Object.entries(agg.byCat)) {
                out[cat] = {
                  equip: v.equip,
                  seg: v.seg,
                  addon: v.addon,
                  taxa: v.equip > 0 ? v.seg / v.equip : 0,
                };
              }
              return out;
            });
        }
        // Merge N-1 (mesmo dia do mês) → injecta equipN1/segN1/taxaN1 em cada day + cada categoria
        function _mergeN1(currentArr, n1Arr) {
          const n1ByDay = new Map(n1Arr.map(d => [d.day, d]));
          for (const d of currentArr) {
            const prev = n1ByDay.get(d.day);
            if (!prev) continue;
            d.total.equipN1 = prev.total.equip;
            d.total.segN1   = prev.total.seg;
            d.total.taxaN1  = prev.total.taxa;
            // Categorias
            for (const k of Object.keys(d)) {
              if (k === 'day' || k === 'dateSerial' || k === 'hasData' || k === 'total') continue;
              const pCat = prev[k];
              if (!pCat) continue;
              d[k].equipN1 = pCat.equip;
              d[k].segN1   = pCat.seg;
              d[k].taxaN1  = pCat.taxa;
            }
          }
          return currentArr;
        }
        const dailyByStore = {};
        for (const [store, dateMap] of bdStoreMap) {
          dailyByStore[store] = _mapToArray(dateMap);
        }
        const dailyAllStores = _mapToArray(bdAllMap);
        const dailyByStoreN1 = {};
        for (const [store, dateMap] of bdStoreMapN1) {
          dailyByStoreN1[store] = _mapToArray(dateMap);
        }
        const dailyAllStoresN1 = _mapToArray(bdAllMapN1);
        // Aplica merge: cada loja current ↔ mesma loja N-1
        for (const store of Object.keys(dailyByStore)) {
          if (dailyByStoreN1[store]) _mergeN1(dailyByStore[store], dailyByStoreN1[store]);
        }
        _mergeN1(dailyAllStores, dailyAllStoresN1);

        const dd = _ddrFromFilename(file.name);

        // v3.21.28: derivar ano/mês reais a partir do workbook (Excel serials)
        // em vez de confiar apenas no filename — fix para casos como
        // "Mai_27" onde 27 = dia de geração e não ano 2027.
        let workbookYmd = null;
        // P1: BD N → primeira data com dados
        for (const [, dateMap] of bdStoreMap) {
          const firstSerial = Array.from(dateMap.keys())[0];
          const ymd = _ymdFromSerial(firstSerial);
          if (ymd) { workbookYmd = ymd; break; }
        }
        // P2: RESUMO DIA primeira linha com data
        if (!workbookYmd && daily.length > 0 && daily[0].dateN) {
          workbookYmd = _ymdFromSerial(daily[0].dateN);
        }
        let monthKey = dd.monthKey;
        let monthLabel = dd.month || 'Mês não detectado';
        let snapshotDay = null;
        if (workbookYmd) {
          monthKey = `${workbookYmd.year}-${String(workbookYmd.month).padStart(2, '0')}`;
          const monthsAbbr = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
          monthLabel = `${monthsAbbr[workbookYmd.month - 1]}/${String(workbookYmd.year).slice(-2)}`;
          // Filename day hint (se ≤ 31 e diferente dos últimos 2 dígitos do ano)
          const fileNumMatch = file.name.match(/(?:jan|fev|mar|abr|mai|jun|jul|ago|set|out|nov|dez)[_\- ]+(\d{1,2})\b/i);
          const fileNum = fileNumMatch ? Number(fileNumMatch[1]) : null;
          if (fileNum && fileNum >= 1 && fileNum <= 31 && fileNum !== workbookYmd.year % 100) {
            snapshotDay = fileNum;
          }
        }

        resolve({
          month: monthLabel,
          monthKey,
          snapshotDay,
          importedAt: new Date().toISOString(),
          filename: file.name,
          stores, total,
          sellers,
          sellerStoreFilter,
          budgets,
          // v3.21.16: novos campos
          daily,
          vim,
          churn,
          sellerChurn,
          priceScales,
          clusters,
          targetsDaily,
          // v3.21.18: equipamentos sem seguro
          uninsured,
          familySummary,
          // v3.21.19: por colaborador
          uninsuredBySeller,
          // v3.21.23: daily real por loja (de BD N)
          dailyByStore,
          dailyAllStores,
          dailyByStoreN1,
          dailyAllStoresN1,
        });
      } catch (err) { reject(err); }
    };
    reader.onerror = () => reject(reader.error);
    reader.readAsArrayBuffer(file);
  });
}

// Cloud: 1 linha por (store_id, month_key). Admin-only via RLS.
async function cloudUploadPenetrationSnapshot({ storeId, snap, userId }) {
  if (!supabase || !snap) return { ok: false, error: 'sem supabase/snap' };
  const payload = {
    store_id: storeId || null,
    month_key: snap.monthKey,
    filename: snap.filename,
    imported_by: userId || null,
    payload: snap,
  };
  const { error } = await supabase.from('penetration_snapshots').upsert(payload, {
    onConflict: 'store_id,month_key',
  });
  return { ok: !error, error: error?.message };
}

async function cloudFetchPenetrationSnapshots({ storeId, limit = 12 } = {}) {
  if (!supabase) return [];
  let q = supabase.from('penetration_snapshots').select('*').order('month_key', { ascending: false }).limit(limit);
  if (storeId) q = q.eq('store_id', storeId);
  const { data, error } = await q;
  if (error) { console.warn('cloudFetchPenetrationSnapshots:', error.message); return []; }
  return data || [];
}

async function cloudDeletePenetrationSnapshot(id) {
  if (!supabase || !id) return { ok: false };
  const { error } = await supabase.from('penetration_snapshots').delete().eq('id', id);
  return { ok: !error, error: error?.message };
}

function toIsoDate(ddmmyyyy) {
  // "01-01-2026" → "2026-01-01"
  const m = ddmmyyyy.match(/^(\d{2})-(\d{2})-(\d{4})$/);
  return m ? `${m[3]}-${m[2]}-${m[1]}` : null;
}

// ─────────────────────────────────────────────────────────────────────────
// FNAC counter-sales parser — "Vendas de artigos detalhados ao mostrador"
// 10 colunas: EAN, Descrição, Unidades, PVP Total, Funcionario, Nome, Data,
// Familia 1, Familia 2, Familia 3.
// Famílias com SEGUROS = seguro base. SEGUROS ADDON = PP/extensão.
// Funcionario 994 = vendas anónimas (Nome vazio).
// ─────────────────────────────────────────────────────────────────────────
function parseCounterSalesExcel(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const XLSX = await getXLSX();
        const wb = XLSX.read(new Uint8Array(e.target.result), { type: 'array', cellDates: true });
        const sheetName = wb.SheetNames.find(n => /vendas/i.test(n)) || wb.SheetNames[0];
        if (!sheetName) return reject(new Error('Sem sheet no ficheiro'));
        const aoa = XLSX.utils.sheet_to_json(wb.Sheets[sheetName], { header: 1, blankrows: false, defval: null });
        if (aoa.length < 5) return reject(new Error('Ficheiro vazio ou formato inesperado'));

        const metaLine2 = (aoa[1] || []).filter(Boolean).join(' ');
        const metaLine3 = (aoa[2] || []).filter(Boolean).join(' ');
        const periodMatch = metaLine2.match(/Data:\s*(\d{2}-\d{2}-\d{4})\s*at[ée]\s*(\d{2}-\d{2}-\d{4})/i);
        const storeMatch  = metaLine3.match(/Loja:\s*(.+?)(?:\s*(?:Valor|Unidades|$))/i);
        const dateFrom = periodMatch ? toIsoDate(periodMatch[1]) : null;
        const dateTo   = periodMatch ? toIsoDate(periodMatch[2]) : null;
        const storeName = storeMatch ? storeMatch[1].trim() : '—';

        const headers = (aoa[3] || []).map(h => String(h || '').trim().toLowerCase());
        const idx = (patterns) => headers.findIndex(h => patterns.some(p => h.includes(p)));
        const cEan   = idx(['ean']);
        const cName  = idx(['descri']);
        const cQty   = idx(['unidades', 'unid']);
        const cPvp   = idx(['pvp']);
        const cFunc  = idx(['funcion']);
        const cWho   = idx(['nome']);
        const cDate  = idx(['data']);
        const cFam1  = idx(['famila 1', 'família 1', 'familia 1']);
        const cFam2  = idx(['famila 2', 'família 2', 'familia 2']);
        const cFam3  = idx(['famila 3', 'família 3', 'familia 3']);

        if (cEan < 0 || cName < 0 || cQty < 0 || cPvp < 0 || cFunc < 0) {
          return reject(new Error('Cabeçalho não tem as colunas esperadas.'));
        }

        const rows = [];
        for (let r = 4; r < aoa.length; r++) {
          const row = aoa[r];
          if (!row) continue;
          const ean = row[cEan];
          if (ean == null || ean === '') continue;
          const qty   = Number(row[cQty]) || 0;
          const value = Number(row[cPvp]) || 0;
          const fam1  = cFam1 >= 0 ? String(row[cFam1] || '').trim() : '';
          // Tipo: produto / seguro (descrição começa por "SEG") /
          //       addon (descrição começa por "PP" — extensões de garantia,
          //       NÃO confundir com Planos de Proteção, que são geridos à parte
          //       na vista 'Planos de Proteção').
          const desc = String(row[cName] || '').trim();
          let type = 'product';
          if (/^SEG[\s_]/i.test(desc))      type = 'insurance';
          else if (/^PP[\s_]/i.test(desc))  type = 'addon';
          const funcNum = row[cFunc];
          const who = cWho >= 0 ? String(row[cWho] || '').trim() : '';
          const isAnonymous = !who || String(funcNum) === '994';
          let dateIso = null;
          const rawDate = cDate >= 0 ? row[cDate] : null;
          if (rawDate instanceof Date) dateIso = rawDate.toISOString().slice(0, 10);
          else if (typeof rawDate === 'string' && rawDate.length >= 10) dateIso = rawDate.slice(0, 10);
          rows.push({
            ean: String(ean),
            name: String(row[cName] || '').trim(),
            qty,
            value,
            funcNum: funcNum != null ? String(funcNum) : '',
            who: isAnonymous ? '— Anónimo' : who,
            isAnonymous,
            date: dateIso,
            fam1,
            fam2: cFam2 >= 0 ? String(row[cFam2] || '').trim() : '',
            fam3: cFam3 >= 0 ? String(row[cFam3] || '').trim() : '',
            type,
          });
        }

        const importedAt = new Date().toISOString();
        const id = `counter-${storeName.toLowerCase().replace(/\s+/g, '-')}-${importedAt.replace(/[:.]/g, '')}`;
        resolve({
          id, store: storeName, filename: file.name,
          dateFrom, dateTo, importedAt, rowsCount: rows.length, rows,
        });
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = () => reject(reader.error);
    reader.readAsArrayBuffer(file);
  });
}

// ─────────────────────────────────────────────────────────────────────────
// localStorage helpers — keep tight and safe (preferences, theme, light state)
// ─────────────────────────────────────────────────────────────────────────
const STORE_PREFIX = 'dd_';

function storeGet(key, fallback) {
  if (typeof localStorage === 'undefined') return fallback;
  try {
    const v = localStorage.getItem(STORE_PREFIX + key);
    return v ? JSON.parse(v) : fallback;
  } catch { return fallback; }
}
function storeSet(key, value) {
  if (typeof localStorage === 'undefined') return;
  try { localStorage.setItem(STORE_PREFIX + key, JSON.stringify(value)); } catch {}
}
function storeDelete(key) {
  if (typeof localStorage === 'undefined') return;
  try { localStorage.removeItem(STORE_PREFIX + key); } catch {}
}

// ─── Tombstones (recently-deleted ids) ────────────────────────────────
// Quando o utilizador apaga algo, registamos o id aqui durante 5 min para
// que a sync periódica não ressuscite o item enquanto a cloud ainda tem
// o registo em flight.
const TOMBSTONE_TTL = 5 * 60 * 1000;
function getTombstones(kind) {
  const all = storeGet('tombstones', {});
  const list = all[kind] || [];
  const now = Date.now();
  return list.filter(t => now - t.at < TOMBSTONE_TTL);
}
function addTombstone(kind, id) {
  if (id == null) return;
  const all = storeGet('tombstones', {});
  const fresh = (all[kind] || []).filter(t => Date.now() - t.at < TOMBSTONE_TTL);
  fresh.push({ id: String(id), at: Date.now() });
  all[kind] = fresh.slice(-200);
  storeSet('tombstones', all);
}
function isTombstoned(kind, id) {
  if (id == null) return false;
  return getTombstones(kind).some(t => t.id === String(id));
}

// ─── Templates de campanha ─────────────────────────────────────────────
// Guardam o layout (floors+zones) para reutilizar em campanhas recorrentes
function listTemplates() {
  return storeGet('templates', []);
}
function saveTemplate(name, floors) {
  const list = listTemplates();
  const tpl = {
    id: 'tpl-' + Date.now(),
    name: String(name || 'Sem nome'),
    floors: layoutOnly(floors || []),
    createdAt: new Date().toISOString(),
  };
  list.unshift(tpl);
  storeSet('templates', list.slice(0, 50)); // cap at 50
  return tpl;
}
function deleteTemplate(id) {
  storeSet('templates', listTemplates().filter(t => t.id !== id));
}
function storeListWithPrefix(prefix) {
  if (typeof localStorage === 'undefined') return [];
  const out = [];
  for (let i = 0; i < localStorage.length; i++) {
    const k = localStorage.key(i);
    if (k && k.startsWith(STORE_PREFIX + prefix)) out.push(k.slice(STORE_PREFIX.length));
  }
  return out;
}

// useStoredState — same shape as useState but persists value under storage key
// Read once at mount, write on every change. Use for filters, sort, page size, etc.
function useStoredState(key, defaultValue) {
  const [value, setValue] = useState(() => {
    const stored = storeGet(`ui:${key}`, undefined);
    return stored === undefined ? defaultValue : stored;
  });
  useEffect(() => {
    storeSet(`ui:${key}`, value);
  }, [key, value]);
  return [value, setValue];
}

// ─────────────────────────────────────────────────────────────────────────
// IndexedDB — stores large objects (campaign rows: each ~9MB)
// localStorage maxes out at ~5MB total, so campaign rows go here instead.
// Schema:
//   v1: "campaigns" store (keyed by campaign.key) — Excel uploads
//   v2: + "periods" store (keyed by id) — campaign planning entities
//        + "zone_memory" store (keyed by ean) — remembers where each EAN was assigned
// ─────────────────────────────────────────────────────────────────────────
const IDB_NAME = 'dd_app';
const IDB_VERSION = 4; // v3.20.3: added counter_sales_snapshots store
const IDB_STORE = 'campaigns';
const IDB_STORE_PERIODS = 'periods';
const IDB_STORE_MEMORY = 'zone_memory';
const IDB_STORE_SALES = 'sales_snapshots';
const IDB_STORE_COUNTER_SALES = 'counter_sales_snapshots';

let _idbPromise = null;
function idbOpen() {
  if (typeof indexedDB === 'undefined') return Promise.reject(new Error('No IndexedDB'));
  if (_idbPromise) return _idbPromise;
  _idbPromise = new Promise((resolve, reject) => {
    const req = indexedDB.open(IDB_NAME, IDB_VERSION);
    req.onupgradeneeded = (e) => {
      const db = e.target.result;
      if (!db.objectStoreNames.contains(IDB_STORE)) {
        db.createObjectStore(IDB_STORE, { keyPath: 'key' });
      }
      if (!db.objectStoreNames.contains(IDB_STORE_PERIODS)) {
        db.createObjectStore(IDB_STORE_PERIODS, { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains(IDB_STORE_MEMORY)) {
        db.createObjectStore(IDB_STORE_MEMORY, { keyPath: 'ean' });
      }
      // v3.20.0: snapshot completo de vendas detalhadas (uma loja, um período).
      // 1 doc por upload; isActive: true marca o que aparece na vista.
      if (!db.objectStoreNames.contains(IDB_STORE_SALES)) {
        const store = db.createObjectStore(IDB_STORE_SALES, { keyPath: 'id' });
        store.createIndex('isActive', 'isActive');
      }
      // v3.20.3: vendas ao mostrador (com colaborador). Estrutura igual ao sales,
      // mas com campos diferentes: funcionario, name, sem PMP, etc.
      if (!db.objectStoreNames.contains(IDB_STORE_COUNTER_SALES)) {
        const store = db.createObjectStore(IDB_STORE_COUNTER_SALES, { keyPath: 'id' });
        store.createIndex('isActive', 'isActive');
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
  return _idbPromise;
}

async function idbPut(item) {
  if (CLOUD_ONLY) return; // skip IDB writes in cloud-only mode
  const db = await idbOpen();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(IDB_STORE, 'readwrite');
    tx.objectStore(IDB_STORE).put(item);
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
}

