  campaigns: { roles: ['user', 'manager', 'viewer'], visible: true },
  calendar: { roles: ['user', 'manager', 'viewer'], visible: true },
  changes: { roles: ['user', 'manager'], visible: true },
  stock: { roles: ['user', 'manager'], visible: true },
  inventory: { roles: ['user', 'manager', 'viewer'], visible: true },
  images: { roles: ['user', 'manager'], visible: true },
  pdfs: { roles: ['user', 'manager'], visible: true },
  notes: { roles: ['user', 'manager', 'viewer'], visible: true },
  // v3.15.3: Cofre de credenciais — admin-only por defeito. Admin pode
  // activar `visible` e escolher que roles vêm a opção na sidebar/Cmd+K.
  // (RLS continua a garantir que só vêem o que podem ler.)
  credentials: { roles: [], visible: false },
  // v3.17.0: vistas PES — gated pelo hideFor/showFor da Sidebar, não pelo uiConfig.
  // Default visible=true para que admin sempre veja na sidebar.
  novidades:  { roles: ['user', 'manager', 'viewer'], visible: true },
  devolucoes: { roles: ['user', 'manager', 'viewer'], visible: true },
  scanner: { visible: true, roles: ['user', 'manager', 'viewer'] },
  // v3.19.0: Planos de Proteção — admin-only, PTS-only.
  // canSeeMenuItem trata o admin como sempre visível; hideFor: ['PES'] no Sidebar
  // exclui visão PES. Para non-admins fica invisível por defeito (roles vazio).
