// ─────────────────────────────────────────────────────────────────────────
// Store Layout — pisos + zonas/móveis (geríveis pelo admin)
// Substitui o DEFAULT_FLOORS hardcoded. Schema: ver supabase/migrations/
// 2026-05-12_store_layout.sql
// ─────────────────────────────────────────────────────────────────────────
async function cloudFetchStoreLayout(department, storeId) {
  if (!supabase) return null;
  try {
    // store_floors: por loja (cada loja tem o seu próprio layout físico).
    // store_zones: por dept dentro da loja (PTS e PES têm zonas diferentes).
    // v3.21.6: filtro por store_id quando fornecido.
    let floorsQ = supabase.from('store_floors').select('*').order('display_order', { ascending: true });
    let zonesQ  = supabase.from('store_zones').select('*').order('display_order', { ascending: true });
    if (storeId) floorsQ = floorsQ.eq('store_id', storeId);
    if (storeId) zonesQ = zonesQ.eq('store_id', storeId);
    if (department) zonesQ = zonesQ.eq('department', department);
    const [floorsRes, zonesRes] = await Promise.all([
      floorsQ,
      zonesQ,
    ]);
    if (floorsRes.error) {
      console.warn('cloudFetchStoreLayout(floors):', floorsRes.error.message);
      return null;
    }
    if (zonesRes.error) {
      console.warn('cloudFetchStoreLayout(zones):', zonesRes.error.message);
      return null;
    }
    let floors = floorsRes.data || [];
    const zones  = zonesRes.data  || [];
    // v3.20.10: PES não usa "destaques portáteis" (floors com star=true).
    // Pisos normais (piso 1, piso 0, etc.) continuam partilhados.
    if (department === 'PES') {
      floors = floors.filter(f => !f.star);
    }
    // Build the same shape as DEFAULT_FLOORS so FloorPlanner/Blueprint don't change
    return floors.map(f => ({
      id: f.id,
      name: f.name,
      color: f.color || '#5DA050',
      star: !!f.star,
      zones: zones
        .filter(z => z.floor_id === f.id)
        .map(z => ({ id: z.id, name: z.name, slots: [] })),
    }));
  } catch (e) {
    console.warn('cloudFetchStoreLayout failed:', e);
    return null;
  }
}

