// ─────────────────────────────────────────────────────────────────────────
// Blueprint — visual overview of store mobiliário with assignment status
// Shows: floors, zones grouped by floor, fill state per zone (color-coded),
// and miniature cards for assigned products inside each zone.
// Pulls data from currently loaded campaigns (combines all of them).
// ─────────────────────────────────────────────────────────────────────────

// Generate a deterministic color from a string (for product placeholder accent)
function hashColor(str) {
  if (!str) return '#999';
  let h = 0;
  for (let i = 0; i < str.length; i++) h = (h * 31 + str.charCodeAt(i)) | 0;
  const hues = [10, 25, 40, 60, 90, 130, 170, 200, 230, 260, 290, 320, 350];
  const hue = hues[Math.abs(h) % hues.length];
  return `hsl(${hue}, 55%, 50%)`;
}

// Try to find an image URL column in campaign rows (heuristic; usually absent)
function findImageColumn(headers) {
  if (!headers) return null;
  return headers.find(h => /^(imagem|image|foto|photo|url.?img|picture|thumb)/i.test(h)) || null;
}

// Compute combined floors with all assigned slots from all campaigns
// Returns: [{ floor, zones: [{ zone, slots, productInfo: [...] }] }]
function buildBlueprint(campaigns, defaultLayout, periods) {
  // Start with defaultLayout structure (zones)
  const base = (defaultLayout || []).map(f => ({
    ...f,
    zones: f.zones.map(z => ({ ...z, slots: [] })),
  }));

  // Build EAN → product details lookup from all campaigns
  const productsByEan = new Map();
  campaigns.forEach(camp => {
    if (!camp.rows) return;
    const cols = detectColumns(camp.headers || []);
    const imgCol = findImageColumn(camp.headers || []);
    camp.rows.forEach(r => {
      const ean = String(r[cols.ean] ?? '').trim();
      const key = normalizeEAN(ean);
      if (!key || productsByEan.has(key)) return;
      const basePriceVal = parseNum(cols.basePrice ? r[cols.basePrice] : 0);
      const campPriceVal = parseNum(cols.campaignPrice ? r[cols.campaignPrice] : 0);
      productsByEan.set(key, {
        ean,
        eanKey: key,
        family: cols.family ? String(r[cols.family] ?? '').trim() : '',
        description: cols.description ? String(r[cols.description] ?? '').trim() : '',
        basePrice: basePriceVal,
        campaignPrice: campPriceVal,
        imageUrl: imgCol ? String(r[imgCol] ?? '').trim() : '',
        campaignName: camp.name,
        isStar: cols.star ? isStarValue(r[cols.star]) : false,
      });
    });
  });

  // Helper: aggregate slots from a floors structure into base. Slots whose EAN
  // is NOT present in any campaign's rows are skipped — these are stale
  // assignments left behind after re-uploads/deletions and would otherwise
  // appear as "sem dados" entries that mislead the user. (v3.10.4)
  //
  // v3.15.4: match também por NAME (case-insensitive) quando o id não bate.
  // Necessário porque após o admin correr cloudSeedDefaultLayout, o
  // defaultLayout passa a ter UUIDs gerados pela DB, mas os períodos
  // existentes ainda têm IDs hardcoded ('piso0', 'p1z1', etc). Sem este
  // fallback, o Blueprint aparece vazio porque o base.find por id falha.
  const normName = (s) => String(s || '').trim().toLowerCase();
  const ingestFloors = (floors, sourceLabel) => {
    if (!Array.isArray(floors)) return;
    floors.forEach(f => {
      const baseFloor =
        base.find(bf => bf.id === f.id) ||
        base.find(bf => normName(bf.name) === normName(f.name));
      if (!baseFloor) return;
      (f.zones || []).forEach(z => {
        const baseZone =
          baseFloor.zones.find(bz => bz.id === z.id) ||
          baseFloor.zones.find(bz => normName(bz.name) === normName(z.name));
        if (!baseZone) return;
        (z.slots || []).forEach(s => {
          const refKey = normalizeEAN(s.ref);
          if (!refKey) return;
          const product = productsByEan.get(refKey);
          if (!product) return; // EAN not in any campaign — skip
          if (baseZone.slots.some(bs => normalizeEAN(bs.ref) === refKey)) return;
          baseZone.slots.push({ ...s, product, sourceCampaign: sourceLabel });
        });
      });
    });
  };

  // Plan ownership lives on the PERIOD now (v3.x). Aggregate slots from every
  // period's floors first; legacy campaign-level floors are kept as fallback
  // so that older data still appears.
  (periods || []).forEach(p => {
    if (p.hidden) return;
    if (p.floors && Array.isArray(p.floors)) ingestFloors(p.floors, p.name || 'Período');
  });
  campaigns.forEach(camp => {
    if (!camp.floors) return;
    ingestFloors(camp.floors, camp.name);
  });

  return base;
}

// ─────────────────────────────────────────────────────────────────────────
// GlobalSearch — overlay tipo Cmd+K (v3.12.0)
// Pesquisa em períodos, campanhas, produtos (EAN/desc/família) e atalhos
// Navega com ↑↓, abre com Enter, fecha com Esc.
// ─────────────────────────────────────────────────────────────────────────
function GlobalSearch({ campaigns, periods, stockRowsPO2, stockRowsPO3, isAdmin, uiConfig, userProfile, onClose, onNavigatePeriod, onNavigateView }) {
  const [query, setQuery] = useState('');
  const [activeIdx, setActiveIdx] = useState(0);
  const [credentials, setCredentials] = useState([]); // v3.15.3: lazy load on mount
  const inputRef = useRef(null);
  const listRef = useRef(null);

  useEffect(() => {
    inputRef.current && inputRef.current.focus();
  }, []);

  // v3.15.3: carrega credenciais ao abrir o palette (best-effort, sem bloquear UI).
  // RLS garante que só vemos as nossas (ou tudo, se admin). Mostramos apenas o
  // nome no Cmd+K — passwords nunca aparecem aqui.
  useEffect(() => {
    let alive = true;
    if (!canSeeMenuItem('credentials', userProfile?.role || 'user', isAdmin, uiConfig)) return;
    cloudFetchCredentials().then(list => {
      if (alive) setCredentials(Array.isArray(list) ? list : []);
    }).catch(() => { /* silencioso */ });
    return () => { alive = false; };
  }, [isAdmin, userProfile?.role, uiConfig]);

  // Items navegáveis (atalhos para vistas)
  const userRole = userProfile?.role || 'user';
  const viewItems = useMemo(() => {
    const all = [
      { id: 'dashboard', label: 'Visão Geral', kind: 'view' },
      { id: 'sales', label: 'Análise de Vendas', kind: 'view' },
      { id: 'campaigns', label: 'Campanhas', kind: 'view' },
      { id: 'calendar', label: 'Calendário', kind: 'view' },
      { id: 'changes', label: 'Alterações', kind: 'view' },
      { id: 'stock', label: 'Stock', kind: 'view' },
      { id: 'inventory', label: 'Inventário', kind: 'view' },
      { id: 'images', label: 'Folhetos', kind: 'view' },
      { id: 'pdfs', label: 'PDFs', kind: 'view' },
      { id: 'notes', label: 'Notas', kind: 'view' },
      { id: 'credentials', label: 'Cofre', kind: 'view' }, // v3.15.3
    ];
    if (isAdmin) all.push({ id: 'admin', label: 'Administração', kind: 'view' });
    return all.filter(it => canSeeMenuItem(it.id, userRole, isAdmin, uiConfig));
  }, [isAdmin, userRole, uiConfig]);

  // Build search results
  const results = useMemo(() => {
    const q = query.trim().toLowerCase();
    const out = [];

    // 1. Atalhos de menu — sempre que match label
    if (q) {
      viewItems.forEach(v => {
        if (v.label.toLowerCase().includes(q)) {
          out.push({ kind: 'view', id: v.id, label: v.label, sub: 'Ir para' });
        }
      });
    }

    // 2. Períodos por nome
    const periodMatches = (periods || []).filter(p => {
      if (!q) return false;
      return (p.name || '').toLowerCase().includes(q);
    }).slice(0, 8);
    periodMatches.forEach(p => {
      const st = periodStatus(p);
      const stLabel = PERIOD_STATUS_LABEL[st] || '';
      out.push({ kind: 'period', id: p.id, label: p.name, sub: stLabel + (p.startDate ? ' · ' + formatPeriodDates(p) : '') });
    });

    // 3. Campanhas (Excels) por nome
    const campaignMatches = (campaigns || []).filter(c => {
      if (!q) return false;
      return (c.name || '').toLowerCase().includes(q) || (c.key || '').toLowerCase().includes(q);
    }).slice(0, 8);
    campaignMatches.forEach(c => {
      const period = (periods || []).find(p => p.id === c.periodId);
      out.push({
        kind: 'campaign', id: c.id, periodId: c.periodId,
        label: c.name, sub: (period ? period.name : 'Sem período') + ' · ' + ((c.rows || []).length) + ' produtos',
      });
    });

    // 4. Produtos (limitar a 30 para não rebentar) — só procura se q tem ≥ 2 caracteres
    if (q.length >= 2) {
      const prodOut = [];
      const seen = new Set();
      const isNumeric = /^\d+$/.test(q);
      const limit = 30;
      outer: for (const c of campaigns || []) {
        if (!c.rows || !c.headers) continue;
        const cols = detectColumns(c.headers);
        for (const r of c.rows) {
          const ean = String(r[cols.ean] || '').trim();
          const eanK = normalizeEAN(ean);
          if (!eanK) continue;
          if (seen.has(eanK)) continue;
          const descr = cols.description ? String(r[cols.description] || '') : '';
          const fam = cols.family ? String(r[cols.family] || '') : '';
          let match = false;
          if (isNumeric && eanK.includes(normalizeEAN(q))) match = true;
          else if (descr.toLowerCase().includes(q)) match = true;
          else if (fam.toLowerCase().includes(q)) match = true;
          if (!match) continue;
          seen.add(eanK);
          const period = (periods || []).find(p => p.id === c.periodId);
          // v3.15.4: incluir preço de campanha + desconto no sub (visibilidade
          // imediata sem precisar de abrir Alterações). Se não houver preço,
          // o subParts.filter(Boolean) descarta a string vazia.
          const basePrice = cols.basePrice ? parseNum(r[cols.basePrice]) : 0;
          const campPrice = cols.campaignPrice ? parseNum(r[cols.campaignPrice]) : 0;
          const pct = (basePrice > 0 && campPrice > 0 && campPrice < basePrice)
            ? Math.round((1 - campPrice / basePrice) * 100)
            : 0;
          const priceStr = campPrice
            ? `${campPrice.toFixed(2)}€${pct ? ` (-${pct}%)` : ''}`
            : (basePrice ? `${basePrice.toFixed(2)}€` : '');
          const subParts = [ean, fam, period?.name, priceStr].filter(Boolean);
          prodOut.push({
            kind: 'product', id: eanK, ean,
            label: descr || ean,
            sub: subParts.join(' · '),
            periodId: c.periodId,
          });
          if (prodOut.length >= limit) break outer;
        }
      }
      out.push(...prodOut);
    }

    // 5. Credenciais (cofre) — v3.15.3
    // Procura por nome, username, url, tags. Nunca mostra a password.
    if (q && credentials.length > 0) {
      const credOut = [];
      for (const cred of credentials) {
        const haystack = [
          cred.name, cred.username, cred.url,
          ...(Array.isArray(cred.tags) ? cred.tags : []),
        ].filter(Boolean).join(' ').toLowerCase();
        if (!haystack.includes(q)) continue;
        const typeLabel = (CREDENTIAL_TYPES.find(t => t.id === cred.type)?.label) || 'Credencial';
        credOut.push({
          kind: 'credential', id: cred.id,
          label: cred.name || 'Sem nome',
          sub: typeLabel + (cred.username ? ' · ' + cred.username : '') + (cred.url ? ' · ' + cred.url : ''),
        });
        if (credOut.length >= 8) break;
      }
      out.push(...credOut);
    }

    return out;
  }, [query, campaigns, periods, viewItems, credentials]);

  // Reset índice activo quando muda a query
  useEffect(() => { setActiveIdx(0); }, [query]);

  // Scroll do item activo para a vista
  useEffect(() => {
    const el = listRef.current && listRef.current.querySelector('[data-active="true"]');
    if (el) el.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
  }, [activeIdx]);

  const onKeyDown = (e) => {
    if (e.key === 'ArrowDown') { e.preventDefault(); setActiveIdx(i => Math.min(i + 1, results.length - 1)); }
    else if (e.key === 'ArrowUp') { e.preventDefault(); setActiveIdx(i => Math.max(i - 1, 0)); }
    else if (e.key === 'Enter') { e.preventDefault(); openResult(results[activeIdx]); }
  };

  const openResult = (r) => {
    if (!r) return;
    if (r.kind === 'view') onNavigateView(r.id);
    else if (r.kind === 'period') onNavigatePeriod(r.id);
    else if (r.kind === 'campaign') {
      // v3.15.4: deep link — CampaignsView lê este id ao montar e activa só
      // esta campanha (setOnlyActive), abrindo o detalhe automaticamente.
      try { sessionStorage.setItem('campaigns.openCampaignId', r.id); } catch {}
      if (r.periodId) onNavigatePeriod(r.periodId);
      else onNavigateView('campaigns');
    } else if (r.kind === 'product') {
      // v3.15.4: navega para Alterações com o EAN pré-filtrado e
      // destacado — o utilizador vê preço actual + última alteração.
      try {
        sessionStorage.setItem('changes.searchEan', r.ean);
        sessionStorage.setItem('changes.highlightEan', r.ean);
      } catch {}
      onNavigateView('changes');
    } else if (r.kind === 'credential') {
      // v3.15.3: vai para o cofre. A credencial não é auto-revelada;
      // o utilizador clica no item para revelar (auditoria preservada).
      try { sessionStorage.setItem('credentials.highlight', r.id); } catch {}
      onNavigateView('credentials');
    }
  };

  // Suggestion chips quando query vazia
  const showSuggestions = !query.trim();

  return (
    <div onClick={onClose} style={{
      position: 'fixed', inset: 0, background: 'rgba(20,18,16,0.55)',
      zIndex: 300, display: 'flex', alignItems: 'flex-start', justifyContent: 'center',
      paddingTop: 'min(12vh, 80px)', paddingLeft: 12, paddingRight: 12,
      animation: 'fadeIn 0.15s ease-out',
    }}>
      <style>{`@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }`}</style>
      <div onClick={e => e.stopPropagation()} style={{
        background: T.bg, borderRadius: 12,
        width: 'min(640px, 100%)', maxHeight: '70vh',
        display: 'flex', flexDirection: 'column',
        border: `1px solid ${T.line}`,
        boxShadow: '0 30px 70px -20px rgba(0,0,0,0.4)',
        overflow: 'hidden',
      }}>
        {/* Input */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '14px 18px', borderBottom: `1px solid ${T.line}` }}>
          <Search size={16} style={{ color: T.inkMute, flexShrink: 0 }} />
          <input
            ref={inputRef}
            value={query}
            onChange={e => setQuery(e.target.value)}
            onKeyDown={onKeyDown}
            placeholder="Pesquisar campanhas, períodos, EAN, produtos, cofre…"
            style={{
              flex: 1, border: 'none', background: 'transparent', outline: 'none',
              fontSize: 16, color: T.ink, fontFamily: 'inherit',
            }}
          />
          <span className="mono" style={{ fontSize: 9, padding: '3px 6px', background: T.bgEl, color: T.inkMute, borderRadius: 4, letterSpacing: '0.08em', flexShrink: 0 }}>
            ESC
          </span>
        </div>

        {/* Results */}
        <div ref={listRef} style={{ flex: 1, overflowY: 'auto', minHeight: 0 }}>
          {showSuggestions ? (
            <div style={{ padding: 14 }}>
              <div className="mono" style={{ fontSize: 9, letterSpacing: '0.15em', color: T.inkMute, textTransform: 'uppercase', marginBottom: 10 }}>
                Atalhos rápidos
              </div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                {viewItems.map(v => (
                  <button key={v.id} onClick={() => onNavigateView(v.id)} style={{
                    padding: '7px 12px', fontSize: 12, fontWeight: 500,
                    background: T.bgEl, border: `1px solid ${T.line}`,
                    borderRadius: 6, cursor: 'pointer', fontFamily: 'inherit', color: T.ink,
                  }}>
                    {v.label}
                  </button>
                ))}
              </div>
              <div style={{ marginTop: 18, fontSize: 11, color: T.inkMute, lineHeight: 1.6 }}>
                <div><kbd style={kbdStyle}>↑</kbd> <kbd style={kbdStyle}>↓</kbd> navegar · <kbd style={kbdStyle}>Enter</kbd> abrir · <kbd style={kbdStyle}>Esc</kbd> fechar</div>
                <div style={{ marginTop: 4 }}>Atalhos: <kbd style={kbdStyle}>Ctrl</kbd>+<kbd style={kbdStyle}>K</kbd> ou <kbd style={kbdStyle}>/</kbd> abrem esta pesquisa em qualquer página.</div>
              </div>
            </div>
          ) : results.length === 0 ? (
            <div style={{ padding: '40px 20px', textAlign: 'center', color: T.inkMute, fontSize: 13 }}>
              Sem resultados para <strong style={{ color: T.ink }}>"{query}"</strong>.
            </div>
          ) : (
            results.map((r, i) => {
              const active = i === activeIdx;
              const KindIcon =
                r.kind === 'view' ? ChevronRight :
                r.kind === 'period' ? Calendar :
                r.kind === 'campaign' ? Layers :
                r.kind === 'credential' ? KeyRound :
                Tag; // product
              const kindColor =
                r.kind === 'view' ? T.inkMute :
                r.kind === 'period' ? T.green :
                r.kind === 'campaign' ? T.accent :
                r.kind === 'credential' ? '#7B5EA8' :
                '#0ea5e9';
              return (
                <button
                  key={r.kind + ':' + r.id + ':' + i}
                  data-active={active ? 'true' : 'false'}
                  onMouseEnter={() => setActiveIdx(i)}
                  onClick={() => openResult(r)}
                  style={{
                    width: '100%', display: 'flex', alignItems: 'center', gap: 12,
                    padding: '10px 18px', background: active ? T.bgEl : 'transparent',
                    border: 'none', borderLeft: `3px solid ${active ? kindColor : 'transparent'}`,
                    cursor: 'pointer', fontFamily: 'inherit', textAlign: 'left',
                  }}
                >
                  <div style={{ width: 28, height: 28, borderRadius: 6, background: T.bgEl, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                    <KindIcon size={14} strokeWidth={1.6} style={{ color: kindColor }} />
                  </div>
                  <div style={{ minWidth: 0, flex: 1 }}>
                    <div style={{ fontSize: 13, fontWeight: 500, color: T.ink, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {r.label}
                    </div>
                    <div style={{ fontSize: 11, color: T.inkMute, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {r.sub}
                    </div>
                  </div>
                  <span className="mono" style={{ fontSize: 9, color: T.inkMute, letterSpacing: '0.08em', textTransform: 'uppercase', flexShrink: 0 }}>
                    {r.kind === 'view' ? 'Atalho'
                      : r.kind === 'period' ? 'Período'
                      : r.kind === 'campaign' ? 'Excel'
                      : r.kind === 'credential' ? 'Cofre'
                      : 'Produto'}
                  </span>
                </button>
              );
            })
          )}
        </div>
      </div>
    </div>
  );
}

const kbdStyle = {
  display: 'inline-block', padding: '1px 5px', background: T.bgEl,
  border: `1px solid ${T.line}`, borderRadius: 3,
  fontFamily: 'Geist Mono', fontSize: 10, color: T.inkSoft,
};

function BlueprintPanel({ campaigns, defaultLayout, periods, onClose }) {
  const [expandedZone, setExpandedZone] = useState(null); // zoneId of detail open
  const [filterFloor, setFilterFloor] = useStoredState('blueprint.filterFloor', 'all');
  const [filterStatus, setFilterStatus] = useStoredState('blueprint.filterStatus', 'all'); // all | filled | empty | partial

  useEffect(() => {
    const onKey = (e) => { if (e.key === 'Escape') onClose(); };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onClose]);

  const blueprint = useMemo(
    () => buildBlueprint(campaigns, defaultLayout, periods),
    [campaigns, defaultLayout, periods]
  );

  // Compute global stats
  const stats = useMemo(() => {
    let totalZones = 0;
    let filledZones = 0;
    let emptyZones = 0;
    let totalSlots = 0;
    const conflictsByEan = new Map();
    blueprint.forEach(f => {
      f.zones.forEach(z => {
        totalZones++;
        if (z.slots.length === 0) emptyZones++;
        else filledZones++;
        totalSlots += z.slots.length;
        z.slots.forEach(s => {
          const k = normalizeEAN(s.ref);
          if (!k) return;
          conflictsByEan.set(k, (conflictsByEan.get(k) || 0) + 1);
        });
      });
    });
    const conflicts = [...conflictsByEan.entries()].filter(([_, n]) => n > 1).length;
    return { totalZones, filledZones, emptyZones, totalSlots, conflicts };
  }, [blueprint]);

  // Apply filters
  const filteredBlueprint = useMemo(() => {
    return blueprint
      .filter(f => filterFloor === 'all' || f.id === filterFloor)
      .map(f => ({
        ...f,
        zones: f.zones.filter(z => {
          if (filterStatus === 'filled' && z.slots.length === 0) return false;
          if (filterStatus === 'empty' && z.slots.length > 0) return false;
          return true;
        }),
      }));
  }, [blueprint, filterFloor, filterStatus]);

  return (
    <>
      <div onClick={onClose} style={{
        position: 'fixed', inset: 0, background: 'rgba(20,18,16,0.45)',
        zIndex: 95, animation: 'fadeUp 0.15s ease-out',
      }} />
      <div style={{
        position: 'fixed', top: 24, right: 24, bottom: 24, zIndex: 96,
        width: 'min(880px, calc(100vw - 48px))',
        background: T.bg, borderRadius: 12,
        border: `1px solid ${T.line}`,
        boxShadow: '0 24px 48px -12px rgba(0,0,0,0.3)',
        display: 'flex', flexDirection: 'column',
        animation: 'fadeUp 0.18s ease-out',
        overflow: 'hidden',
      }}>
        {/* Header */}
        <div style={{
          padding: '16px 24px', background: T.bgEl, borderBottom: `1px solid ${T.line}`,
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        }}>
          <div>
            <div className="mono" style={{ fontSize: 10, letterSpacing: '0.15em', color: T.accent, textTransform: 'uppercase', marginBottom: 4 }}>
              Vista da loja
            </div>
            <h3 className="display" style={{ fontSize: 24, margin: 0, fontStyle: 'italic' }}>Blueprint</h3>
          </div>
          <button onClick={onClose} style={{
            padding: 6, background: 'transparent', border: 'none', color: T.inkMute, borderRadius: 4,
          }}><X size={18} /></button>
        </div>

        {/* Stats bar */}
        <div style={{
          padding: '14px 24px', background: T.bg, borderBottom: `1px solid ${T.lineSoft}`,
          display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 12,
        }}>
          <BPStat label="Móveis" value={stats.totalZones} />
          <BPStat label="Em uso" value={stats.filledZones} accent={T.green} />
          <BPStat label="Vazios" value={stats.emptyZones} accent={stats.emptyZones > 0 ? T.orange : T.inkMute} />
          <BPStat label="Produtos" value={stats.totalSlots} accent={T.accent} />
        </div>

        {/* Filters */}
        <div style={{
          padding: '10px 20px', borderBottom: `1px solid ${T.line}`,
          display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'center',
        }}>
          <span className="mono" style={{ fontSize: 9, color: T.inkMute, letterSpacing: '0.1em', textTransform: 'uppercase' }}>Piso:</span>
          <button onClick={() => setFilterFloor('all')} style={chipBtn(filterFloor === 'all')}>Todos</button>
          {blueprint.map(f => (
            <button key={f.id} onClick={() => setFilterFloor(f.id)} style={chipBtn(filterFloor === f.id, f.color)}>
              {f.name}
            </button>
          ))}
          <span style={{ width: 1, height: 16, background: T.line, margin: '0 4px' }} />
          <span className="mono" style={{ fontSize: 9, color: T.inkMute, letterSpacing: '0.1em', textTransform: 'uppercase' }}>Estado:</span>
          {[
            { id: 'all', l: 'Todos' },
            { id: 'filled', l: 'Com produtos' },
            { id: 'empty', l: 'Vazios' },
          ].map(s => (
            <button key={s.id} onClick={() => setFilterStatus(s.id)} style={chipBtn(filterStatus === s.id)}>
              {s.l}
            </button>
          ))}
        </div>

        {/* Content */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '20px 24px' }}>
          {campaigns.length === 0 ? (
            <div style={{
              padding: 60, textAlign: 'center', color: T.inkMute,
            }}>
              <MapPin size={32} strokeWidth={1.25} style={{ opacity: 0.5, marginBottom: 12 }} />
              <div style={{ fontSize: 14, fontWeight: 500, color: T.ink, marginBottom: 4 }}>Sem campanhas carregadas</div>
              <div style={{ fontSize: 12 }}>
                Carrega campanhas em "Campanhas" para ver os móveis com produtos atribuídos.
              </div>
            </div>
          ) : filteredBlueprint.every(f => f.zones.length === 0) ? (
            <div style={{ padding: 40, textAlign: 'center', color: T.inkMute, fontSize: 13 }}>
              Sem móveis para os filtros atuais.
            </div>
          ) : filteredBlueprint.map(floor => floor.zones.length > 0 && (
            <BPFloor
              key={floor.id}
              floor={floor}
              expandedZone={expandedZone}
              setExpandedZone={setExpandedZone}
            />
          ))}
        </div>
      </div>
    </>
  );
}

function BPStat({ label, value, accent }) {
  return (
    <div style={{
      padding: '8px 12px', background: T.bgEl, borderRadius: 6,
      border: `1px solid ${T.line}`,
    }}>
      <div className="mono" style={{ fontSize: 8, letterSpacing: '0.12em', color: T.inkMute, textTransform: 'uppercase' }}>{label}</div>
      <div className="display" style={{
        fontSize: 22, lineHeight: 1, fontStyle: 'italic',
        color: accent || T.ink, marginTop: 3,
      }}>
        {value.toLocaleString('pt-PT')}
      </div>
    </div>
  );
}

function chipBtn(active, accentColor) {
  return {
    padding: '4px 10px', fontSize: 10, fontWeight: 500,
    background: active ? (accentColor || T.ink) : 'transparent',
    color: active ? '#fff' : T.inkSoft,
    border: `1px solid ${active ? (accentColor || T.ink) : T.line}`,
    borderRadius: 4, cursor: 'pointer',
    fontFamily: 'inherit',
  };
}

function BPFloor({ floor, expandedZone, setExpandedZone }) {
  const filledCount = floor.zones.filter(z => z.slots.length > 0).length;
  const totalCount = floor.zones.length;
  const slotCount = floor.zones.reduce((s, z) => s + z.slots.length, 0);

  return (
    <div style={{ marginBottom: 28 }}>
      {/* Floor header bar */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 10, marginBottom: 12,
        paddingBottom: 8, borderBottom: `2px solid ${floor.color}`,
      }}>
        <div style={{
          width: 6, height: 24, background: floor.color, borderRadius: 1,
        }} />
        <div style={{ flex: 1 }}>
          <div className="mono" style={{ fontSize: 9, letterSpacing: '0.15em', color: T.inkMute, textTransform: 'uppercase' }}>Piso</div>
          <div style={{ fontSize: 16, fontWeight: 600, color: T.ink }}>{floor.name}</div>
        </div>
        <div className="mono" style={{ fontSize: 11, color: T.inkSoft, textAlign: 'right' }}>
          {filledCount}/{totalCount} móveis · {slotCount} produtos
        </div>
      </div>

      {/* Zone grid */}
      <div style={{
        display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: 10,
      }}>
        {floor.zones.map(zone => (
          <BPZone
            key={zone.id}
            zone={zone}
            floorColor={floor.color}
            expanded={expandedZone === zone.id}
            onToggleExpand={() => setExpandedZone(expandedZone === zone.id ? null : zone.id)}
          />
        ))}
      </div>
    </div>
  );
}

function BPZone({ zone, floorColor, expanded, onToggleExpand }) {
  const count = zone.slots.length;
  // Visual fill state — pure cosmetic (we don't know "expected" capacity)
  const isEmpty = count === 0;
  const isPartial = count > 0 && count < 4;
  const isFilled = count >= 4;

  const stateColor = isEmpty ? T.inkMute : (isPartial ? T.orange : T.green);
  const stateBg = isEmpty ? T.bgEl : (isPartial ? '#FFF5E6' : '#E8F4E5');
  const stateLabel = isEmpty ? 'Vazio' : (isPartial ? `${count} ${count === 1 ? 'produto' : 'produtos'}` : `${count} produtos`);

  return (
    <div style={{
      background: T.paper,
      border: `1px solid ${expanded ? T.accent : T.line}`,
      borderLeft: `3px solid ${floorColor}`,
      borderRadius: 6,
      overflow: 'hidden',
      transition: 'all 0.15s',
    }}>
      <button
        onClick={onToggleExpand}
        style={{
          width: '100%', textAlign: 'left',
          padding: '10px 12px',
          background: 'transparent', border: 'none',
          cursor: count > 0 ? 'pointer' : 'default',
          fontFamily: 'inherit',
        }}
      >
        <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: 8, marginBottom: 6 }}>
          <div style={{
            fontSize: 11, fontWeight: 600, color: T.ink,
            flex: 1, lineHeight: 1.3,
          }}>
            {zone.name}
          </div>
          {count > 0 && (
            <ChevronRight
              size={14}
              style={{
                color: T.inkMute, flexShrink: 0,
                transform: expanded ? 'rotate(90deg)' : 'rotate(0deg)',
                transition: 'transform 0.15s',
              }}
            />
          )}
        </div>
        <div style={{
          display: 'inline-flex', alignItems: 'center', gap: 4,
          padding: '2px 6px', background: stateBg, color: stateColor,
          borderRadius: 3, fontSize: 9, fontWeight: 600, letterSpacing: '0.05em',
          fontFamily: 'Geist Mono', textTransform: 'uppercase',
        }}>
          <span style={{
            width: 5, height: 5, borderRadius: '50%', background: stateColor,
          }} />
          {stateLabel}
        </div>
      </button>

      {/* Mini preview — first 4 products always visible (now showing EAN + name) */}
      {count > 0 && !expanded && (
        <div style={{ padding: '0 12px 10px', display: 'flex', flexDirection: 'column', gap: 3 }}>
          {zone.slots.slice(0, 4).map((s, i) => (
            <BPSlotMini key={i} slot={s} />
          ))}
          {count > 4 && (
            <div style={{
              padding: '3px 8px', fontSize: 10, fontFamily: 'Geist Mono',
              color: T.inkMute, fontStyle: 'italic',
            }}>
              + {count - 4} {count - 4 === 1 ? 'artigo' : 'artigos'}…
            </div>
          )}
        </div>
      )}

      {/* Expanded — full list */}
      {expanded && count > 0 && (
        <div style={{
          padding: '4px 8px 10px',
          borderTop: `1px solid ${T.lineSoft}`,
          display: 'flex', flexDirection: 'column', gap: 4,
        }}>
          {zone.slots.map((s, i) => (
            <BPSlotFull key={i} slot={s} />
          ))}
        </div>
      )}
    </div>
  );
}

// Tiny inline product card — used for the always-visible preview
function BPSlotMini({ slot }) {
  const p = slot.product;
  const color = hashColor(p?.eanKey || slot.ref);
  const ean = String(slot.ref || '').trim();
  const eanShort = ean.length > 13 ? ean.slice(-13) : ean;
  const name = p?.description || '';
  const nameShort = name.length > 30 ? name.slice(0, 30) + '…' : name;
  return (
    <div
      title={`${name || 'Sem descrição'} · ${ean}`}
      style={{
        display: 'flex', flexDirection: 'column',
        padding: '4px 8px', borderRadius: 4,
        background: T.paper,
        border: `1px solid ${T.lineSoft}`,
        borderLeft: `3px solid ${color}`,
        fontFamily: 'Geist Mono, monospace',
        fontSize: 10, lineHeight: 1.3,
        minWidth: 0, maxWidth: 240,
        gap: 1,
      }}
    >
      <span style={{
        color: T.ink, fontWeight: 500, fontFamily: 'Geist, sans-serif',
        overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
        fontSize: 11,
      }}>
        {nameShort || <span style={{ color: T.inkMute, fontStyle: 'italic' }}>sem dados</span>}
      </span>
      <span style={{
        color: T.inkMute, fontSize: 9,
        overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
      }}>
        {eanShort || '—'}
        {p?.isStar && <Star size={8} fill={T.yellow} stroke="none" style={{ marginLeft: 4, verticalAlign: 'middle' }} />}
      </span>
    </div>
  );
}

// Larger product row — used in expanded view
function BPSlotFull({ slot }) {
  const p = slot.product;
  const letter = (p?.description || slot.ref || '?').charAt(0).toUpperCase();
  const color = hashColor(p?.eanKey || slot.ref);
  const hasImage = p?.imageUrl && /^https?:\/\//.test(p.imageUrl);
  return (
    <div style={{
      display: 'flex', alignItems: 'center', gap: 8,
      padding: '5px 6px', borderRadius: 4,
      background: T.bg,
    }}>
      <div style={{
        width: 32, height: 32, borderRadius: 4,
        background: hasImage ? T.lineSoft : color,
        color: '#fff', fontSize: 12, fontWeight: 700,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontFamily: 'Geist Mono', flexShrink: 0,
        backgroundImage: hasImage ? `url(${p.imageUrl})` : 'none',
        backgroundSize: 'cover', backgroundPosition: 'center',
      }}>
        {!hasImage && letter}
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{
          fontSize: 11, fontWeight: 500, color: T.ink,
          overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
        }}>
          {p?.description || <span style={{ color: T.inkMute, fontStyle: 'italic' }}>Sem dados</span>}
        </div>
        <div className="mono" style={{
          fontSize: 9, color: T.inkMute, marginTop: 1,
          display: 'flex', gap: 6, alignItems: 'center',
        }}>
          <span>{slot.ref || '—'}</span>
          {p?.campaignPrice > 0 && (
            <>
              <span>·</span>
              <span style={{ color: T.accent, fontWeight: 600 }}>
                €{p.campaignPrice.toFixed(2).replace('.', ',')}
              </span>
            </>
          )}
          {p?.isStar && <Star size={9} fill={T.yellow} stroke="none" />}
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────
// PenetrationView (v3.21.11) — admin-only. Mostra taxa de penetração
// mensal: linha desta loja + média da companhia + breakdown por categoria.
// ─────────────────────────────────────────────────────────────────────────
function pctFmt(v) { return `${(Number(v) * 100).toFixed(1)}%`; }
function pctDelta(v) {
  const n = Number(v) * 100;
  const sign = n > 0 ? '+' : '';
  return `${sign}${n.toFixed(1)}pp`;
}

function PenetrationView({ currentStoreId, currentStoreName, currentUserId, embedded = false }) {
  const [snapshots, setSnapshots] = useState([]); // todos os meses na cloud
  const [loading, setLoading] = useState(true);
  const [importing, setImporting] = useState(false);
  const [importError, setImportError] = useState(null);
  const [importProgress, setImportProgress] = useState(null);
  const [selectedMonthKey, setSelectedMonthKey] = useStoredState('penetration.month', null);

  const refresh = useCallback(async () => {
    setLoading(true);
    const list = await cloudFetchPenetrationSnapshots({ limit: 24 });
    setSnapshots(list);
    if (list.length > 0 && !selectedMonthKey) setSelectedMonthKey(list[0].month_key);
    setLoading(false);
  }, [selectedMonthKey, setSelectedMonthKey]);
  useEffect(() => { refresh(); }, []); // eslint-disable-line

  const active = useMemo(
    () => snapshots.find(s => s.month_key === selectedMonthKey) || snapshots[0] || null,
    [snapshots, selectedMonthKey]
  );
  const snap = active?.payload || null;
  // v3.21.14: snapshot anterior (N-1) — mês imediatamente anterior ao seleccionado
  const prevSnap = useMemo(() => {
    if (!active) return null;
    const idx = snapshots.findIndex(s => s.month_key === active.month_key);
    if (idx < 0 || idx >= snapshots.length - 1) return null;
    return snapshots[idx + 1].payload || null; // snapshots vem ordenado desc
  }, [active, snapshots]);

  // Linha desta loja (tenta currentStoreName, fallback "AVEIRO")
  const myStoreRow = useMemo(() => {
    if (!snap) return null;
    const target = (currentStoreName || 'AVEIRO').toUpperCase().replace(/^FNAC\s+/, '').trim();
    return snap.stores.find(s => s.name.toUpperCase().includes(target))
        || snap.stores.find(s => s.name.toUpperCase().includes('AVEIRO'))
        || null;
  }, [snap, currentStoreName]);

  const handleFile = async (file) => {
    setImporting(true); setImportError(null);
    setImportProgress({ stage: 'parse', message: 'A ler RESUMO…' });
    try {
      const newSnap = await parsePenetrationExcel(file, (p) => setImportProgress(p));
      if (!newSnap.monthKey) {
        setImportError('Não detectei o mês no nome do ficheiro. Renomeia para algo como "TX_Penetração_Mai_26.xlsx".');
        return;
      }
      setImportProgress({ stage: 'cloud-upload', message: 'A guardar na cloud…' });
      const r = await cloudUploadPenetrationSnapshot({ storeId: currentStoreId, snap: newSnap, userId: currentUserId });
      if (!r.ok) throw new Error(r.error || 'erro a guardar');
      await refresh();
      setSelectedMonthKey(newSnap.monthKey);
    } catch (err) {
      setImportError(err.message || String(err));
    } finally {
      setImporting(false); setImportProgress(null);
    }
  };

  const handleDelete = async (id) => {
    if (!confirm('Apagar este snapshot mensal?')) return;
    await cloudDeletePenetrationSnapshot(id);
    refresh();
  };

  if (loading) return <div style={{ padding: 60, textAlign: 'center', color: T.inkMute }}>A carregar…</div>;

  return (
    <div className={embedded ? '' : 'fade-up'}>
      {!embedded && (
        <Header
          title="Taxa de Penetração"
          subtitle="Análise mensal da loja vs. média da companhia (sheet RESUMO do ficheiro TX_Penetração)"
        />
      )}

      {/* v3.21.13: Toolbar minimalista — chips inline em vez de card pesado */}
      <div style={{ display: 'flex', gap: 16, alignItems: 'center', marginBottom: 28, flexWrap: 'wrap' }}>
        {snapshots.length > 0 && (
          <>
            <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', alignItems: 'center' }}>
              {snapshots.slice(0, 8).map(s => {
                const on = s.month_key === selectedMonthKey;
                return (
                  <button key={s.id} onClick={() => setSelectedMonthKey(s.month_key)}
                    style={{
                      padding: '5px 12px', fontSize: 11, fontFamily: 'inherit',
                      borderRadius: 999, fontWeight: 500,
                      border: `1px solid ${on ? T.ink : T.line}`,
                      background: on ? T.ink : 'transparent',
                      color: on ? T.bg : T.inkSoft, cursor: 'pointer',
                    }}>
                    {s.payload?.month || s.month_key}
                  </button>
                );
              })}
            </div>
            {active && (
              <span style={{ fontSize: 10, color: T.inkMute, fontFamily: 'Geist Mono' }}>
                · {new Date(active.imported_at).toLocaleDateString('pt-PT')}
              </span>
            )}
          </>
        )}
        <div style={{ flex: 1 }} />
        <label style={{ cursor: importing ? 'wait' : 'pointer', padding: '7px 14px', background: 'transparent', color: T.ink, borderRadius: 6, fontSize: 12, fontWeight: 500, display: 'inline-flex', alignItems: 'center', gap: 6, border: `1px solid ${T.line}` }}>
          <Upload size={12} /> {importing ? (importProgress?.message || 'A processar…') : (active ? 'Actualizar' : 'Sobe ficheiro')}
          <input type="file" accept=".xlsx,.xls" disabled={importing} style={{ display: 'none' }} onChange={e => { const f = e.target.files?.[0]; if (f) handleFile(f); e.target.value = ''; }} />
        </label>
        {active && (
          <button onClick={() => handleDelete(active.id)} title="Apagar este mês" style={{ padding: '7px 10px', background: 'transparent', color: T.inkMute, border: `1px solid ${T.line}`, borderRadius: 6, fontSize: 11, cursor: 'pointer' }}>
            <Trash2 size={11} />
          </button>
        )}
      </div>

      {importError && (
        <div style={{ padding: 12, marginBottom: 16, background: `${T.red}15`, color: T.red, borderRadius: 6, fontSize: 12, border: `1px solid ${T.red}40` }}>
          <AlertCircle size={12} style={{ display: 'inline', verticalAlign: 'text-bottom', marginRight: 6 }} />
          {importError}
        </div>
      )}

      {!snap ? (
        <div style={{ padding: '80px 24px', textAlign: 'center' }}>
          <TrendingUp size={28} strokeWidth={1.5} style={{ color: T.inkMute, marginBottom: 18, opacity: 0.5 }} />
          <div className="display" style={{ fontSize: 22, fontWeight: 500, color: T.ink, marginBottom: 8, letterSpacing: '-0.02em' }}>
            Sem dados ainda
          </div>
          <div style={{ fontSize: 13, color: T.inkMute, maxWidth: 380, margin: '0 auto', lineHeight: 1.6 }}>
            Sobe o ficheiro mensal <span style={{ fontFamily: 'Geist Mono', color: T.inkSoft }}>TX_Penetração_&lt;Mês&gt;_&lt;Ano&gt;.xlsx</span> para começares a comparar Aveiro com a média da companhia.
          </div>
        </div>
      ) : !myStoreRow ? (
        <div style={{ padding: 24, background: `${T.orange}10`, border: `1px solid ${T.orange}40`, borderRadius: 8, color: T.orange }}>
          <AlertTriangle size={14} style={{ display: 'inline', verticalAlign: 'text-bottom', marginRight: 6 }} />
          Não encontrei "{currentStoreName || 'AVEIRO'}" na lista de lojas do ficheiro. Lojas disponíveis: {snap.stores.map(s => s.name).join(', ')}.
        </div>
      ) : (
        <PenetrationBreakdown snap={snap} myStoreRow={myStoreRow} prevSnap={prevSnap} />
      )}
    </div>
  );
}

// Componente que renderiza a comparação detalhada por categoria
// v3.21.14: helpers para diarização
// _workingDaysInMonth, _daysRemainingInMonth, _hoursFromCarga → app/lib/helpers.js (v3.23.0)

// v3.21.16: cor consoante TP — 3 níveis (heatmap)
function _tpColor(taxa) {
  const v = Number(taxa) || 0;
  if (v >= 0.40) return T.green;
  if (v >= 0.25) return T.orange;
  return T.red;
}
function _tpBg(taxa) {
  const v = Number(taxa) || 0;
  if (v >= 0.40) return `${T.green}18`;
  if (v >= 0.25) return `${T.orange}14`;
  if (v > 0)     return `${T.red}10`;
  return 'transparent';
}
function _isPTS(seller) {
  // Match case-insensitive 'PT' no início → apanha PTs, PTS, Pts
  return /^pt/i.test(seller?.dept || '');
}
function _fmtEur(n) {
  const v = Number(n) || 0;
  return v.toLocaleString('pt-PT', { maximumFractionDigits: 0 }) + ' €';
}

// v3.21.18: infere família a partir da descrição (heurística) ou cod_fam
function _famFromDesc(desc, codFam) {
  const d = String(desc || '').toUpperCase();
  if (/\b(TELM|TELEM|TELEMOV|SMTP|SMARTPHONE|TLM)\b/.test(d)) return 'Telecom';
  if (/\b(TV|LCD|LED|OLED|QLED|MONITOR)\b/.test(d))           return 'TV/Vídeo';
  if (/\b(SMARTWATCH|SMTWATCH|WATCH)\b/.test(d))              return 'Smartwatch';
  if (/\b(TABLET|TAB)\b/.test(d))                              return 'Tablet';
  if (/\b(NOTEB|PORTATIL|LAPTOP|MACBOOK|DESKTOP|PC\s)/.test(d))return 'Hardware';
  if (/\b(FOTO|CAMARA|CAMERA|GOPRO|LENTE|REFLEX|MIRROR)\b/.test(d)) return 'Foto';
  if (/\b(DRONE|DJI|MAVIC)\b/.test(d))                         return 'Drone';
  if (/\b(CONSOLA|PS5|XBOX|SWITCH|GAMING|PLAYSTATION|NINTENDO)\b/.test(d)) return 'Gaming';
  if (/\b(TROTI|SCOOTER|BIKE|BICICLETA|ELETRICA|XIAOMI\s+MI)\b/.test(d)) return 'Mob.Eléctrica';
  if (/\b(IPAD)\b/.test(d))                                    return 'Tablet';
  if (/\b(IPHONE)\b/.test(d))                                  return 'Telecom';
  // Fallback: usar código família (9730 = Telecom)
  if (String(codFam) === '9730') return 'Telecom';
  return 'Outras';
}

